window.APUNTES_DATA = {"bloques": [{"id": "fundamentos", "titulo": "Fundamentos", "desc": "Las bases del lenguaje", "rango": [1, 12]}, {"id": "es6", "titulo": "ES6", "desc": "JavaScript moderno (2015+)", "rango": [13, 29]}, {"id": "regex", "titulo": "Expresiones Regulares", "desc": "Patrones de texto", "rango": [30, 40]}, {"id": "debug", "titulo": "Debugging", "desc": "Encontrar y corregir errores", "rango": [41, 45]}, {"id": "data", "titulo": "Estructuras de Datos", "desc": "Manipular arrays y objetos", "rango": [46, 51]}, {"id": "algoritmos", "titulo": "Algoritmos Básicos", "desc": "Resolver problemas paso a paso", "rango": [52, 60]}, {"id": "oop", "titulo": "Programación Orientada a Objetos", "desc": "Constructores, herencia y módulos", "rango": [61, 75]}, {"id": "funcional", "titulo": "Programación Funcional", "desc": "Funciones puras, inmutabilidad y composición", "rango": [76, 86]}], "secciones": [{"numero": 1, "titulo": "Variables y Tipos de Datos", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Declaración de variables"}, {"tipo": "codigo", "codigo": "//las 3 formas de declarar variables\nvar nombre = \"Jose\";     //forma antigua, mejor evitarla\nlet edad = 21;            //puede cambiar despues\nconst ciudad = \"CDMX\";    //no puede volver a cambiar, es constante\n\n//ejemplo de por que const es mejor cuando el valor no cambia\nconst IVA = 0.16          //esto nunca deberia cambiar en el programa"}, {"tipo": "subtitulo", "texto": "Operadores de asignación compuesta"}, {"tipo": "tabla", "filas": [["**Forma larga**", "**Forma corta (equivalente)**"], ["a = a + 1;", "a++;"], ["a = a + 67;", "a += 67;"], ["a = a - 5;", "a -= 5;"], ["a = a * 3;", "a *= 3;"], ["a = a / 2;", "a /= 2;"]]}]}, {"numero": 2, "titulo": "Cadenas de Texto (Strings)", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Comillas dentro de strings"}, {"tipo": "texto", "texto": "Para incluir comillas dobles dentro de un string, usa la barra invertida \\:"}, {"tipo": "codigo", "codigo": "//usando comillas dobles para poder meter comillas simples dentro\nlet frase = \"Mi profe dijo: \\\"aprueban todos\\\"\""}, {"tipo": "subtitulo", "texto": "Concatenación"}, {"tipo": "codigo", "codigo": "//concatenando con + y +=\nconst curso = \"freeCodeCamp\"\nlet mensaje = \"Estoy estudiando \" + curso\nmensaje += \" y me esta gustando mucho\""}, {"tipo": "subtitulo", "texto": "Largo de una cadena — .length"}, {"tipo": "codigo", "codigo": "//sacando la longitud de un string\nlet nombre = \"Jose Armando\"\nconsole.log(nombre.length)   //13, cuenta hasta los espacios"}, {"tipo": "subtitulo", "texto": "Acceso por índice (inicia en 0)"}, {"tipo": "codigo", "codigo": "//accediendo a caracteres por su indice\nlet nombre = \"Jose Armando\"\nnombre[0]                  //\"J\" el primer caracter\nnombre[nombre.length - 1]  //\"o\" el ultimo caracter, sin saber cuanto mide el string"}, {"tipo": "subtitulo", "texto": "Secuencias de escape"}, {"tipo": "tabla", "filas": [["**Secuencia**", "**Qué hace**"], ["\\n", "Nueva línea"], ["\\t", "Tabulación (sangría)"], ["\\\\", "Barra invertida literal \\"], ["\\\"", "Comillas dobles dentro de string"], ["\\'", "Comilla simple dentro de string"], ["\\r", "Retorno de carro (regresa al inicio)"], ["\\b", "Retroceso (borra carácter anterior)"]]}]}, {"numero": 3, "titulo": "Arrays (Arreglos)", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Declaración"}, {"tipo": "codigo", "codigo": "//creando arrays de distintos tipos\nconst numeros = [1, 2, 3]\nconst frutas = [\"manzana\", \"pera\", \"uva\"]\nconst matriz = [[1, 2], [3, 4]]    //array dentro de otro array"}, {"tipo": "subtitulo", "texto": "Acceso y modificación"}, {"tipo": "codigo", "codigo": "//accediendo y modificando por indice\nnumeros[0]        //1, el primer elemento\nmatriz[0][1]      //2, fila 0 columna 1\nnumeros[0] = 99   //los arrays si son mutables aunque sean const"}, {"tipo": "subtitulo", "texto": "Métodos principales"}, {"tipo": "tabla", "filas": [["**Método**", "**Qué hace**"], ["arr.push(x)", "Agrega x al FINAL del array"], ["arr.pop()", "Elimina y devuelve el ÚLTIMO elemento"], ["arr.shift()", "Elimina y devuelve el PRIMER elemento"], ["arr.unshift(x)", "Agrega x al INICIO del array"]]}]}, {"numero": 4, "titulo": "Funciones", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Sintaxis básica"}, {"tipo": "codigo", "codigo": "//estructura basica de una funcion\nfunction procesarDatos(dato1, dato2) {\n  //aqui va la logica\n  return dato1 + dato2\n}\nprocesarDatos(5, 3)   //llamando la funcion con argumentos"}, {"tipo": "subtitulo", "texto": "Conceptos clave"}, {"tipo": "texto", "texto": "- Parámetros = variables al definir la función (los 'espacios reservados')"}, {"tipo": "texto", "texto": "- Argumentos = valores reales que pasas al llamarla"}, {"tipo": "texto", "texto": "- Sin return → la función devuelve undefined"}, {"tipo": "texto", "texto": "- Con return → devuelve el valor indicado y termina la función"}, {"tipo": "subtitulo", "texto": "Alcance (Scope)"}, {"tipo": "tabla", "filas": [["**Global**", "**Local**"], ["Variable declarada fuera de función. Visible en todo el código.", "Variable declarada dentro de función. Solo existe dentro de ella."], ["let x = 5; // global", "function f() {   let x = 99; // local }"]]}, {"tipo": "nota", "texto": "**⚠️ Regla de conflicto de alcance** Si hay una variable local y global con el mismo nombre, la LOCAL gana dentro de la función."}, {"tipo": "subtitulo", "texto": "Return anticipado (Early Return)"}, {"tipo": "texto", "texto": "Cuando se ejecuta return, la función termina inmediatamente. El código después no se ejecuta."}, {"tipo": "codigo", "codigo": "//ejemplo de por que el return detiene la funcion\nfunction saludar() {\n  console.log(\"Hola\")\n  return \"Adios\"\n  console.log(\"esto nunca se imprime\")  //el return ya termino la funcion\n}"}]}, {"numero": 5, "titulo": "Booleanos y Operadores de Comparación", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Booleanos"}, {"tipo": "texto", "texto": "Solo dos valores posibles: true o false — NUNCA entre comillas (si tienen comillas son texto, no booleanos)."}, {"tipo": "subtitulo", "texto": "Tabla de operadores de comparación"}, {"tipo": "tabla", "filas": [["**Operador**", "**Significado y ejemplo**"], ["==", "Igual **(convierte tipos)**  →  3 == '3' → true"], ["===", "Igual estricto **(sin convertir)**  →  3 === '3' → false"], ["!=", "Diferente **(convierte tipos)**  →  1 != '1' → false"], ["!==", "Diferente estricto  →  3 !== '3' → true"], [">", "Mayor que  →  5 > 3 → true"], [">=", "Mayor o igual que  →  6 >= 6 → true"], ["<", "Menor que  →  5 < 5 → false"], ["<=", "Menor o igual que  →  5 <= 5 → true"]]}, {"tipo": "subtitulo", "texto": "Operadores lógicos"}, {"tipo": "tabla", "filas": [["**Operador**", "**Regla**"], ["&&  (AND)", "true SOLO si AMBAS condiciones son true"], ["││  (OR)", "true si AL MENOS UNA condición es true"], ["!   (NOT)", "Invierte el valor: !true → false"]]}, {"tipo": "nota", "texto": "**💡 Tip — typeof** Para conocer el tipo de un valor: typeof 3 → \"number\" │ typeof '3' → \"string\""}]}, {"numero": 6, "titulo": "Condicionales (if / else if / else)", "bloque": "fundamentos", "contenido": [{"tipo": "codigo", "codigo": "//estructura if / else if / else\nif (edad >= 18) {\n  //se ejecuta si la condicion de arriba es true\n} else if (edad >= 13) {\n  //se ejecuta si la primera fue false pero esta es true\n} else {\n  //si ninguna de las anteriores se cumplio\n}"}, {"tipo": "nota", "texto": "**⚠️ El orden importa** El código se evalúa de arriba abajo. El primer if que sea true detiene la cadena."}, {"tipo": "subtitulo", "texto": "Operador ternario (condicional de una línea)"}, {"tipo": "texto", "texto": "Sintaxis:  condicion ? valor_si_true : valor_si_false"}, {"tipo": "codigo", "codigo": "//ternario como alternativa corta a if/else\nconst mayorDeEdad = (edad >= 18) ? \"Puede entrar\" : \"No puede entrar\""}, {"tipo": "subtitulo", "texto": "Ternarios encadenados (múltiples condiciones)"}, {"tipo": "codigo", "codigo": "//ternarios encadenados para varias condiciones\nconst resultado = (a === b) ? \"son iguales\"\n  : (a > b) ? \"a es mayor\"\n  : \"b es mayor\""}]}, {"numero": 7, "titulo": "Switch", "bloque": "fundamentos", "contenido": [{"tipo": "texto", "texto": "Útil cuando tienes muchas comparaciones sobre el mismo valor. Más limpio que varios if/else if encadenados."}, {"tipo": "codigo", "codigo": "//switch con varios case compartiendo el mismo resultado\nswitch (dia) {\n  case 6:\n  case 7:\n    resultado = \"Fin de semana\"   //sabado y domingo comparten este resultado\n    break\n  case 1:\n    resultado = \"Inicio de semana\"\n    break\n  default:\n    resultado = \"Dia entre semana\"\n}"}, {"tipo": "nota", "texto": "**⚠️ No olvides el break** Sin break, el código sigue ejecutando los cases siguientes (fall-through). Úsalo intencionalmente solo cuando quieras que varios cases compartan código."}]}, {"numero": 8, "titulo": "Objetos (Objects)", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Sintaxis básica"}, {"tipo": "codigo", "codigo": "//creando un objeto con sus propiedades\nconst producto = {\n  nombre: \"Laptop\",\n  precio: 15000,\n  disponible: true,\n  categorias: [\"electronica\", \"oferta\"]\n}"}, {"tipo": "subtitulo", "texto": "Acceso a propiedades"}, {"tipo": "tabla", "filas": [["**Notación de punto (.)**", "**Notación de corchetes ([])**"], ["Cuando conoces el nombre exacto y no tiene espacios.", "Cuando la propiedad tiene espacios, o accedes con una variable."], ["obj.name   // 'Whiskers'", "obj[\"Space Name\"] const prop = 'legs'; obj[prop]  // 4"]]}, {"tipo": "subtitulo", "texto": "Modificar, agregar y eliminar propiedades"}, {"tipo": "codigo", "codigo": "//accediendo y modificando propiedades\nproducto.precio = 13500        //actualizando con punto\nproducto[\"disponible\"] = false //igual pero con corchetes\nproducto.descuento = 0.10      //agregando una propiedad nueva\ndelete producto.descuento      //eliminandola"}, {"tipo": "subtitulo", "texto": "Verificar si una propiedad existe"}, {"tipo": "codigo", "codigo": "//verificando si una propiedad existe antes de usarla\nproducto.hasOwnProperty(\"precio\")   //true\nproducto.hasOwnProperty(\"stock\")    //false, no existe esa propiedad"}, {"tipo": "subtitulo", "texto": "Búsqueda de perfil (lookUpProfile)"}, {"tipo": "texto", "texto": "Función que busca en un array de objetos por nombre y devuelve una propiedad:"}, {"tipo": "codigo", "codigo": "//buscando un dato dentro de un array de objetos\nfunction buscarPropiedad(nombreBuscado, propiedad) {\n  for (let i = 0; i < contactos.length; i++) {\n    if (contactos[i].nombre === nombreBuscado) {\n      if (contactos[i].hasOwnProperty(propiedad)) {\n        return contactos[i][propiedad]\n      } else {\n        return \"Esa propiedad no existe\"\n      }\n    }\n  }\n  return \"No se encontro ese contacto\"\n}"}]}, {"numero": 9, "titulo": "Bucles (Loops)", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "while — ejecuta MIENTRAS la condición sea true"}, {"tipo": "codigo", "codigo": "//recorriendo con while - se repite mientras la condicion sea true\nconst numeros = []\nlet i = 0\nwhile (i < 5) {\n  numeros.push(i)\n  i++       //muy importante no olvidarlo o se queda en loop infinito\n}\n//numeros = [0, 1, 2, 3, 4]"}, {"tipo": "subtitulo", "texto": "for — para un número específico de repeticiones"}, {"tipo": "texto", "texto": "Sintaxis:  for (inicialización; condición; expresión final)"}, {"tipo": "codigo", "codigo": "//for clasico - el mas usado\nfor (let i = 0; i < 5; i++) {\n  numeros.push(i)\n}\n\n//saltando de 2 en 2\nfor (let i = 0; i < 10; i += 2) { /* ... */ }\n\n//cuenta regresiva\nfor (let i = 10; i > 0; i -= 2) { /* ... */ }\n\n//recorriendo un array existente\nfor (let i = 0; i < numeros.length; i++) {\n  console.log(numeros[i])\n}"}, {"tipo": "subtitulo", "texto": "do...while — ejecuta AL MENOS una vez"}, {"tipo": "texto", "texto": "Diferencia clave: el código se ejecuta primero y la condición se evalúa después."}, {"tipo": "codigo", "codigo": "//do-while se ejecuta primero y pregunta despues\nconst arr = []\nlet i = 5\ndo {\n  arr.push(i)   //esto se ejecuta aunque i ya no cumpla la condicion\n  i++\n} while (i < 5)\n//arr = [5] aunque la condicion era falsa desde el inicio"}, {"tipo": "subtitulo", "texto": "for anidado — para arrays multidimensionales"}, {"tipo": "codigo", "codigo": "//bucle anidado para recorrer una matriz completa\nconst matriz = [[1, 2], [3, 4], [5, 6]]\nfor (let i = 0; i < matriz.length; i++) {\n  for (let j = 0; j < matriz[i].length; j++) {\n    console.log(matriz[i][j])\n  }\n}"}]}, {"numero": 10, "titulo": "Recursión", "bloque": "fundamentos", "contenido": [{"tipo": "texto", "texto": "Una función que se llama a sí misma. Siempre necesita un caso base (condición de parada) para no ejecutarse infinitamente."}, {"tipo": "subtitulo", "texto": "Estructura básica"}, {"tipo": "codigo", "codigo": "//estructura de una funcion recursiva\nfunction factorial(n) {\n  if (n <= 0) {          //caso base, aqui se detiene la recursion\n    return 1\n  } else {\n    return factorial(n - 1) * n   //la funcion se llama a si misma\n  }\n}"}, {"tipo": "subtitulo", "texto": "Ejemplo: multiply (equivalente a un for)"}, {"tipo": "codigo", "codigo": "//recursion con un segundo parametro como contador\nfunction multiplicarHasta(arr, n) {\n  if (n <= 0) return 1\n  return multiplicarHasta(arr, n - 1) * arr[n - 1]\n}"}, {"tipo": "subtitulo", "texto": "Ejemplo: countup (genera array [1..n])"}, {"tipo": "codigo", "codigo": "//construyendo un array de forma recursiva\nfunction contarHasta(n) {\n  if (n < 1) return []\n  const arregloContador = contarHasta(n - 1)\n  arregloContador.push(n)\n  return arregloContador\n}\ncontarHasta(5)   //[1, 2, 3, 4, 5]"}, {"tipo": "subtitulo", "texto": "Ejemplo: countdown (genera array [n..1])"}, {"tipo": "codigo", "codigo": "//lo mismo pero al reves con unshift\nfunction contarDesde(n) {\n  if (n < 1) return []\n  const arr = contarDesde(n - 1)\n  arr.unshift(n)\n  return arr\n}\ncontarDesde(5)   //[5, 4, 3, 2, 1]"}, {"tipo": "subtitulo", "texto": "Ejemplo: rangeOfNumbers (genera array [start..end])"}, {"tipo": "codigo", "codigo": "//generando un rango de numeros con recursion\nfunction rangoDeNumeros(inicio, fin) {\n  if (inicio === fin) return [inicio]\n  const arr = rangoDeNumeros(inicio, fin - 1)\n  arr.push(fin)\n  return arr\n}\nrangoDeNumeros(1, 5)   //[1, 2, 3, 4, 5]"}, {"tipo": "nota", "texto": "**💡 Recuerda siempre** Sin caso base → bucle infinito y error. El caso base es lo primero que debes definir."}]}, {"numero": 11, "titulo": "Números Aleatorios", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Fracción aleatoria (0 ≤ x ****<**** 1)"}, {"tipo": "codigo", "codigo": "//numero aleatorio decimal entre 0 y 1\nMath.random()   //ejemplo: 0.374829..."}, {"tipo": "subtitulo", "texto": "Entero aleatorio de 0 a N-1"}, {"tipo": "codigo", "codigo": "//aleatorio entero entre 0 y N usando floor\nMath.floor(Math.random() * 20)   //numero entero de 0 a 19"}, {"tipo": "subtitulo", "texto": "Entero aleatorio dentro de un rango [min, max]"}, {"tipo": "codigo", "codigo": "//generando un rango completo entre un minimo y un maximo\nfunction numeroAleatorioEntre(minimo, maximo) {\n  return Math.floor(Math.random() * (maximo - minimo + 1)) + minimo\n}\nnumeroAleatorioEntre(5, 10)   //numero entero entre 5 y 10 incluidos"}]}, {"numero": 12, "titulo": "parseInt()", "bloque": "fundamentos", "contenido": [{"tipo": "texto", "texto": "Convierte una cadena de texto en un número entero. Si no puede convertirla, devuelve NaN."}, {"tipo": "subtitulo", "texto": "Uso básico"}, {"tipo": "codigo", "codigo": "//parseInt convierte texto a numero entero\nparseInt(\"007\")    //7, ignora los ceros de adelante\nparseInt(\"3.14\")   //3, corta todo lo que sea decimal\nparseInt(\"abc\")    //NaN, no se puede convertir texto sin numeros"}, {"tipo": "subtitulo", "texto": "Con base (radix) — especifica el sistema numérico"}, {"tipo": "codigo", "codigo": "//parseInt tambien puede convertir entre bases numericas\nparseInt(\"11\", 2)    //3   binario a decimal\nparseInt(\"ff\", 16)   //255 hexadecimal a decimal\n//la base puede ir de 2 a 36"}, {"tipo": "subtitulo", "texto": "Arrays — métodos"}, {"tipo": "tabla", "filas": [["push(x)", "Agrega al FINAL"], ["pop()", "Elimina el ÚLTIMO y lo devuelve"], ["shift()", "Elimina el PRIMERO y lo devuelve"], ["unshift(x)", "Agrega al INICIO"]]}, {"tipo": "subtitulo", "texto": "Comparación — referencia rápida"}, {"tipo": "tabla", "filas": [["==  / !=", "Convierte tipos antes de comparar"], ["=== / !==", "NO convierte tipos (estricto)"], ["&&", "AND — ambas deben ser true"], ["││", "OR  — al menos una debe ser true"]]}, {"tipo": "subtitulo", "texto": "Bucles — cuándo usar cuál"}, {"tipo": "tabla", "filas": [["for", "Cuando sabes cuántas veces repetir"], ["while", "Cuando dependes de una condición que puede cambiar"], ["do...while", "Cuando necesitas ejecutar al menos 1 vez"]]}, {"tipo": "subtitulo", "texto": "Acceso a objetos"}, {"tipo": "tabla", "filas": [["obj.prop", "Notación de punto — nombre fijo sin espacios"], ["obj[\"prop\"]", "Corchetes — nombre con espacios o variable"], ["obj[variable]", "Corchetes — cuando el nombre viene de una variable"]]}, {"tipo": "texto", "texto": "ES6 es la versión 6 de ECMAScript (el estándar en que se basa JavaScript), lanzada en 2015. Introdujo herramientas modernas que hacen el código más limpio, corto y predecible. Todo lo que se ve en esta sección es lo que se usa hoy en cualquier proyecto real."}]}, {"numero": 13, "titulo": "var vs let — Alcance (Scope)", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "El alcance define dónde vive una variable. var solo respeta funciones, let respeta cualquier bloque {}. Regla práctica: nunca uses var en código moderno."}, {"tipo": "codigo", "codigo": "//var se escapa del bloque, la funcion completa la contiene\nfor (var i = 0; i < 3; i++) { }\nconsole.log(i)   //3 - i sobrevivio fuera del for, esto es un problema\n\n//let muere al cerrar el bloque {}\nfor (let i = 0; i < 3; i++) { }\nconsole.log(i)   //Error: i is not defined - asi deberia comportarse"}]}, {"numero": 14, "titulo": "const — Constantes", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "const protege la referencia de la variable (no puedes reasignarla), pero el contenido de arrays y objetos sí puede modificarse. Úsala por defecto siempre."}, {"tipo": "codigo", "codigo": "//const no se puede reasignar\nconst precio = 100\nprecio = 150   //Error - no puedes reasignarla\n\n//pero si es un array, el contenido si se puede modificar\nconst carrito = [1, 2, 3]\ncarrito = [4, 5]     //Error - esto no se puede\ncarrito[0] = 99      //esto si funciona, solo cambia el contenido\n\n//cuando usar cada uno\nconst nombreUsuario = \"ghost_dev\"  //no va a cambiar\nconst listaProductos = []          //array que voy a llenar despues\nlet contador = 0                   //este si lo voy a reasignar"}]}, {"numero": 15, "titulo": "Object.freeze — Congelar objetos", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Object.freeze protege el CONTENIDO de un objeto o array. Ni const ni freeze solos son suficientes — juntos ofrecen protección total."}, {"tipo": "codigo", "codigo": "//const protege la referencia pero no el contenido\nconst configuracion = { intentos: 3 }\nconfiguracion.intentos = 99   //esto SI esta permitido, solo con const no alcanza\n\n//con Object.freeze si se protege el contenido\nObject.freeze(configuracion)\nconfiguracion.intentos = 99   //ahora se ignora, el objeto quedo congelado"}, {"tipo": "tabla", "filas": [["", "**Reasignar variable**", "**Modificar contenido**"], ["var / let", "✅ puede", "✅ puede"], ["const", "❌ no puede", "✅ puede"], ["const + freeze", "❌ no puede", "❌ no puede"]]}]}, {"numero": 16, "titulo": "Arrow Functions — Funciones Flecha", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Sintaxis corta para funciones anónimas. Muy usadas como argumentos de map, filter, forEach y similares."}, {"tipo": "codigo", "codigo": "//funcion tradicional\n{\n  const saludar = function(nombre) { return \"Hola \" + nombre }\n}\n\n//arrow function con llaves y return explicito\n{\n  const saludar = (nombre) => { return \"Hola \" + nombre }\n}\n\n//arrow function de una linea, sin llaves ni return\n{\n  const saludar = nombre => \"Hola \" + nombre\n}\n\n//sin parametros los parentesis son obligatorios\nconst saludarATodos = () => \"Hola a todos\"\n\n//con dos o mas parametros tambien son obligatorios\nconst sumar = (a, b) => a + b"}]}, {"numero": 17, "titulo": "Parámetros por Defecto", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Permiten definir un valor de respaldo para un parámetro en caso de que no se pase ningún argumento al invocar la función."}, {"tipo": "codigo", "codigo": "//sin valor por defecto, si no mandas nada llega undefined\n{\n  const saludar = (nombre) => \"Hola \" + nombre\n  saludar()   //\"Hola undefined\"\n}\n\n//con valor por defecto, usa \"amigo\" si no le mandas nada\n{\n  const saludar = (nombre = \"amigo\") => \"Hola \" + nombre\n  saludar()        //\"Hola amigo\"\n  saludar(\"Jose\")  //\"Hola Jose\"\n}"}]}, {"numero": 18, "titulo": "Rest Parameter (...)", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Permite que una función acepte cualquier número de argumentos agrupándolos en un array. Siempre va al final de los parámetros."}, {"tipo": "codigo", "codigo": "//el nombre despues de los tres puntos lo eliges tu\nconst sumarTodo = (...numeros) => numeros.reduce((acumulador, actual) => acumulador + actual, 0)\nsumarTodo(1, 2, 3)         //6\nsumarTodo(1, 2, 3, 4, 5)   //15\n\n//combinado con parametros normales\nconst primeroYResto = (primero, ...resto) => {\n  console.log(primero)   //el primer argumento normal\n  console.log(resto)     //array con todos los demas\n}"}]}, {"numero": 19, "titulo": "Spread Operator (...)", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Expande un array en valores sueltos. Mismo símbolo que rest pero contexto diferente: rest junta, spread expande."}, {"tipo": "codigo", "codigo": "//sin spread no funciona, Math.max no acepta un array directo\nconst calificaciones = [6, 8, 9, 4, 5]\nMath.max(calificaciones)    //NaN\n\n//con spread se expande el array en argumentos individuales\nMath.max(...calificaciones)   //9\n\n//copiando un array de forma independiente\nconst copiaCalificaciones = [...calificaciones]   //dos arrays distintos con el mismo contenido\n\n//el spread solo funciona dentro de algo, no solo\nconst x = ...calificaciones    //Error\nconst x = [...calificaciones]  //correcto"}, {"tipo": "tabla", "filas": [["", "**¿Dónde?**", "**¿Qué hace?**"], ["Rest ...args", "Parámetros de función", "Junta valores sueltos en array"], ["Spread ...arr", "Al invocar o en []", "Expande array en valores sueltos"]]}]}, {"numero": 20, "titulo": "Desestructuración de Objetos", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Extrae propiedades de un objeto y las convierte en variables de forma directa. Evita escribir objeto.propiedad repetidamente."}, {"tipo": "codigo", "codigo": "const usuario = { nombre: \"Jose\", edad: 21, ciudad: \"CDMX\" }\n\n//sin desestructurar, se vuelve repetitivo\n{\n  const nombre = usuario.nombre\n  const edad = usuario.edad\n}\n\n//desestructurando en una sola linea\n{\n  const { nombre, edad } = usuario\n}\n\n//con renombre, usando los dos puntos para cambiar el nombre de la variable\nconst { nombre: nombreUsuario, edad: edadUsuario } = usuario\n\n//tambien funciona con objetos anidados\nconst { direccion: { calle, colonia } } = usuario"}]}, {"numero": 21, "titulo": "Desestructuración de Arrays", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Extrae elementos de un array y los asigna a variables. A diferencia de los objetos, el orden importa."}, {"tipo": "codigo", "codigo": "const numeros = [1, 2, 3, 4, 5]\n\n//tomando solo los primeros dos\nconst [primero, segundo] = numeros\n//primero = 1, segundo = 2\n\n//saltando posiciones con comas vacias\nconst [a, b, , , c] = numeros\n//a=1, b=2, c=5 (se saltaron la posicion 3 y 4)\n\n//intercambiando dos variables sin necesitar una variable temporal\nlet x = 8, y = 6\n[x, y] = [y, x]   //x=6, y=8\n\n//guardando lo que sobra con rest\nconst [primerNumero, segundoNumero, ...resto] = numeros\n//primerNumero=1, segundoNumero=2, resto=[3,4,5]"}]}, {"numero": 22, "titulo": "Desestructuración en Parámetros de Función", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Se puede desestructurar el objeto directamente en el parámetro de la función, evitando un paso extra dentro del cuerpo."}, {"tipo": "codigo", "codigo": "//forma larga, desestructurando adentro de la funcion\n{\n  const mostrarCliente = (cliente) => {\n    const { nombre, edad } = cliente\n    return `${nombre} tiene ${edad} anos`\n  }\n}\n\n//forma corta, desestructurando directo en el parametro\nconst mostrarCliente = ({ nombre, edad }) => `${nombre} tiene ${edad} anos`\n\n//se llama exactamente igual en los dos casos\nmostrarCliente({ nombre: \"Jose\", edad: 21 })"}]}, {"numero": 23, "titulo": "Template Literals — Plantillas de Texto", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Usan comillas invertidas (`) en lugar de comillas normales. Permiten insertar variables con ${} y escribir strings multilínea sin \\n."}, {"tipo": "codigo", "codigo": "const nombre = \"Jose\"\nconst edad = 21\n\n//concatenacion antigua, facil equivocarse con los espacios\n{\n  const mensaje = \"Hola \" + nombre + \", tienes \" + edad + \" anos\"\n}\n\n//con template literal es mucho mas limpio\n{\n  const mensaje = `Hola ${nombre}, tienes ${edad} anos`\n}\n\n//tambien puedes meter operaciones dentro de las llaves\nconst mensajeDoble = `El doble de tu edad es ${edad * 2}`\n\n//multilinea sin necesitar el \\n\nconst texto = `Primera linea\nSegunda linea\nTercera linea`"}]}, {"numero": 24, "titulo": "Notación Abreviada de Objetos", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Cuando el nombre del parámetro y el nombre de la propiedad son iguales, ES6 permite escribirlo solo una vez."}, {"tipo": "codigo", "codigo": "const x = 10, y = 20\n\n//forma larga, repitiendo el nombre de la variable\n{\n  const punto = { x: x, y: y }\n}\n\n//forma corta ES6, si la llave y la variable se llaman igual\n{\n  const punto = { x, y }\n}\n\n//muy util en funciones que arman y devuelven un objeto\nconst crearPunto = (x, y) => ({ x, y })\ncrearPunto(3, 5)   //{ x: 3, y: 5 }"}]}, {"numero": 25, "titulo": "Métodos Concisos en Objetos", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "ES6 permite declarar funciones dentro de objetos sin usar la palabra clave function ni los dos puntos."}, {"tipo": "codigo", "codigo": "//forma antigua, con function y dos puntos\n{\n  const persona = {\n    nombre: \"Ana\",\n    saludar: function() { return \"Hola \" + this.nombre }\n  }\n}\n\n//forma ES6, sin la palabra function ni los dos puntos\n{\n  const persona = {\n    nombre: \"Ana\",\n    saludar() { return `Hola ${this.nombre}` }\n  }\n}"}]}, {"numero": 26, "titulo": "Clases (class)", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Una clase es un molde o plantilla para crear múltiples objetos con la misma estructura. Ideal cuando necesitas crear muchos objetos del mismo tipo."}, {"tipo": "codigo", "codigo": "class Cliente {\n  //el constructor se ejecuta automaticamente cuando usas new\n  constructor(nombre, edad) {\n    this._nombre = nombre   //this es el objeto que se esta creando\n    this._edad = edad\n  }\n\n  //metodo disponible para todas las instancias de la clase\n  saludar() {\n    return `Hola, soy ${this._nombre}`\n  }\n}\n\n//creando objetos a partir de la clase\nconst cliente1 = new Cliente(\"Jose\", 21)\nconst cliente2 = new Cliente(\"Ana\", 30)\n\ncliente1.saludar()   //\"Hola, soy Jose\""}]}, {"numero": 27, "titulo": "Getters y Setters", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "get controla cómo se leen las propiedades de un objeto. set controla cómo se modifican, pudiendo validar o transformar los datos antes de guardarlos. Se usan como propiedades, no como funciones."}, {"tipo": "codigo", "codigo": "class Producto {\n  constructor(precio) {\n    this._precio = precio   //el guion bajo indica que es \"privada\" por convencion\n  }\n\n  //getter - se usa como si fuera una propiedad, sin parentesis\n  get precioConIVA() {\n    return this._precio * 1.16\n  }\n\n  //setter - permite validar antes de guardar el valor\n  set precio(nuevoPrecio) {\n    if (typeof nuevoPrecio !== \"number\" || nuevoPrecio < 0) return\n    this._precio = nuevoPrecio\n  }\n}\n\nconst producto = new Producto(100)\nproducto.precioConIVA    //116 - se usa como propiedad, no como funcion\nproducto.precio = 150    //aqui se dispara el setter y valida antes de guardar"}]}, {"numero": 28, "titulo": "Módulos — export e import", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "ES6 permite compartir código entre archivos JavaScript. Se necesita type='module' en el HTML para activar esta funcionalidad."}, {"tipo": "codigo", "codigo": "<!-- en el HTML, activando los modulos -->\n<script type=\"module\" src=\"app.js\"></script>\n\n// en operaciones.js - exportando\nexport const sumar = (a, b) => a + b\nexport const restar = (a, b) => a - b\n\n// export default para la exportacion principal del archivo\nexport default function multiplicar(a, b) { return a * b }\n\n// en app.js - importando\nimport { sumar, restar } from './operaciones.js'   //solo lo que necesito\nimport * as operaciones from './operaciones.js'    //todo agrupado en un objeto\nimport multiplicar from './operaciones.js'          //el default, sin llaves\n\noperaciones.sumar(2, 3)   //usando el import con *\nsumar(2, 3)               //usando el import selectivo"}, {"tipo": "tabla", "filas": [["**Tipo**", "**Exportar**", "**Importar**"], ["Normal", "export { fn }", "import { fn } from './file.js'"], ["Default", "export default fn", "import fn from './file.js'"], ["Todo", "export { a, b, c }", "import * as obj from './file.js'"]]}]}, {"numero": 29, "titulo": "Promesas (Promise)", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Una promesa representa una operación que tarda tiempo (llamadas a APIs, bases de datos, etc.) y que puede cumplirse o rechazarse. Permiten que el código siga ejecutándose sin bloquearse esperando el resultado."}, {"tipo": "codigo", "codigo": "//creando una promesa\nconst miPromesa = new Promise((resolve, reject) => {\n  //aqui adentro va la operacion que tarda tiempo\n  if (datosObtenidos) {\n    resolve(\"Datos obtenidos correctamente\")   //se cumplio\n  } else {\n    reject(\"Error al obtener los datos\")        //no se cumplio\n  }\n})\n\n//manejando el resultado\nmiPromesa\n  .then(resultado => console.log(resultado))   //se ejecuta si hubo resolve\n  .catch(error => console.log(error))          //se ejecuta si hubo reject"}, {"tipo": "tabla", "filas": [["**Estado**", "**Qué significa**"], ["pending", "Esperando — aún no hay resultado"], ["fulfilled", "resolve() fue llamado — éxito ✅"], ["rejected", "reject() fue llamado — falló ❌"]]}, {"tipo": "texto", "texto": "Las expresiones regulares son patrones que se usan para buscar, validar o manipular texto. En JavaScript se escriben entre diagonales /patron/ y se combinan con metodos como .test() y .match()."}]}, {"numero": 30, "titulo": "Metodos .test() y .match()", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": ".test() verifica si existe una coincidencia y devuelve true o false. .match() extrae las coincidencias y devuelve un array o null. La sintaxis es inversa entre ambos."}, {"tipo": "codigo", "codigo": "//test() - la regex llama al metodo, la cadena va adentro del parentesis\nlet cursoRegex = /Code/\ncursoRegex.test(\"freeCodeCamp\")   //true\ncursoRegex.test(\"Python\")          //false\n\n//match() - al reves, la cadena llama al metodo y la regex va adentro\n\"freeCodeCamp\".match(cursoRegex)   //[\"Code\"]\n\"Python\".match(cursoRegex)          //null\n\n//regla que se me olvidaba al principio: cadena.match(regex), NUNCA regex.match(cadena)"}]}, {"numero": 31, "titulo": "Banderas (Flags)", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Las banderas modifican el comportamiento de la busqueda. Se agregan despues del ultimo / de la regex. Se pueden combinar varias banderas."}, {"tipo": "tabla", "filas": [["**Bandera**", "**Nombre**", "**Que hace**"], ["i", "Case insensitive", "Ignora mayusculas y minusculas"], ["g", "Global", "Encuentra TODAS las coincidencias, no solo la primera"], ["gi", "Ambas", "Todas las coincidencias sin importar mayusculas"]]}, {"tipo": "codigo", "codigo": "//sin bandera, distingue mayusculas de minusculas\n{\n  let saludoRegex = /hola/\n  saludoRegex.test(\"Hola mundo\")   //false, la H esta en mayuscula\n}\n\n//con la bandera i, ya no importa\n{\n  let saludoRegex = /hola/i\n  saludoRegex.test(\"Hola mundo\")   //true\n}\n\n//combinando i (ignora mayusculas) con g (busca todas las coincidencias)\n\"Repite Repite repite\".match(/repite/gi)   //[\"Repite\", \"Repite\", \"repite\"]"}]}, {"numero": 32, "titulo": "Caracteres Especiales y Comodin", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "El punto . es el comodin — coincide con cualquier caracter excepto salto de linea. El operador | funciona como OR para buscar varias alternativas."}, {"tipo": "codigo", "codigo": "//el punto es un comodin, coincide con cualquier caracter\nlet palabraRegex = /hu./\n\"hug\".match(palabraRegex)   //[\"hug\"]\n\"hum\".match(palabraRegex)   //[\"hum\"]\n\n//el OR con | para validar varias opciones completas\nlet respuestaRegex = /si|no|talvez/\nrespuestaRegex.test(\"mi respuesta es si\")   //true\nrespuestaRegex.test(\"mi respuesta es tal vez\")   //false, esta separado con espacio"}]}, {"numero": 33, "titulo": "Clases de Caracteres [ ]", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Los corchetes [] definen un grupo de caracteres posibles en esa posicion. Con ^ adentro se niega la clase. Con - se definen rangos."}, {"tipo": "codigo", "codigo": "//clase normal - busca cualquiera de las letras que pongas dentro\nlet vocalRegex = /b[aeiou]g/\nvocalRegex.test(\"bag\")   //true\nvocalRegex.test(\"big\")   //true\nvocalRegex.test(\"bog\")   //false, la o no esta en la clase\n\n//rango de letras y numeros\nlet letraRegex = /[a-z]/       //cualquier letra minuscula\nlet alfanumericoRegex = /[A-Za-z0-9]/   //letras y numeros juntos\n\n//clase negada con ^ - busca lo que NO este en la lista\nlet noVocalRegex = /[^aeiou]/\nlet noNumeroRegex = /[^0-9]/"}]}, {"numero": 34, "titulo": "Atajos de Clases (Shorthand)", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "JavaScript tiene atajos predefinidos para clases comunes. Minuscula = busca ESO, Mayuscula = busca lo OPUESTO."}, {"tipo": "tabla", "filas": [["**Atajo**", "**Equivalente**", "**Busca**"], ["\\w", "[A-Za-z0-9_]", "Letras, numeros y guion bajo"], ["\\W", "[^A-Za-z0-9_]", "Todo lo que NO es alfanumerico"], ["\\d", "[0-9]", "Solo digitos"], ["\\D", "[^0-9]", "Todo lo que NO es digito"], ["\\s", "[ \\r\\t\\f\\n\\v]", "Espacios en blanco y saltos"], ["\\S", "[^ \\r\\t\\f\\n\\v]", "Todo lo que NO es espacio"]]}, {"tipo": "codigo", "codigo": "//\\w encuentra letras, numeros y guion bajo\n\"Hola_123\".match(/\\w/g)     //[\"H\",\"o\",\"l\",\"a\",\"_\",\"1\",\"2\",\"3\"]\n\n//\\W es lo contrario, todo lo que NO sea \\w\n\"Hola 123!\".match(/\\W/g)    //[\" \", \"!\"]\n\n//\\d encuentra solo digitos\n\"abc123\".match(/\\d/g)       //[\"1\",\"2\",\"3\"]\n\n//\\s encuentra espacios en blanco\n\"abc 123\".match(/\\s/g)      //[\" \"]"}]}, {"numero": 35, "titulo": "Cuantificadores", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Los cuantificadores indican cuantas veces debe aparecer el caracter o grupo anterior."}, {"tipo": "tabla", "filas": [["**Cuantificador**", "**Significado**", "**Ejemplo**"], ["+", "Uno o mas (consecutivos)", "/s+/ en 'Mississippi' → ['ss','ss']"], ["*", "Cero o mas (consecutivos)", "/go*/ en 'gooal' → ['gooo']"], ["?", "Cero o uno (opcional)", "/colou?r/ → 'color' y 'colour'"], ["{n}", "Exactamente n veces", "/a{3}/ → 'aaa'"], ["{n,}", "Minimo n veces", "/a{2,}/ → 'aa', 'aaa', 'aaaa'..."], ["{n,m}", "Entre n y m veces", "/a{2,4}/ → 'aa', 'aaa', 'aaaa'"]]}, {"tipo": "codigo", "codigo": "//+ es uno o mas repeticiones consecutivas\nlet repetidoRegex = /a+/\nrepetidoRegex.test(\"caasa\")   //true, hay una o mas \"a\" seguidas\n\n//* es cero o mas, tambien acepta que no aparezca\nlet ceroOMasRegex = /a*/\nceroOMasRegex.test(\"bcd\")   //true, aunque no haya ninguna \"a\"\n\n//{min,max} para un rango exacto de repeticiones\nlet saludoLargoRegex = /oh{3,6} no/i   //de \"ohhh no\" hasta \"ohhhhhh no\"\n\n//exactamente 4 digitos, ni mas ni menos\nlet cuatroDigitosRegex = /\\d{4}/"}]}, {"numero": 36, "titulo": "Anclas ^ y $", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Las anclas no buscan caracteres, definen la posicion en la cadena. ^ ancla al inicio, $ ancla al final. Juntos validan la cadena completa."}, {"tipo": "codigo", "codigo": "//^ fuera de corchetes significa inicio de la cadena\nlet empiezaRegex = /^Jose/\nempiezaRegex.test(\"Jose Armando\")   //true\nempiezaRegex.test(\"Buscando a Jose\")   //false, no empieza asi\n\n//$ significa final de cadena\nlet terminaRegex = /historia$/\nterminaRegex.test(\"Esto es una historia\")   //true\n\n//combinando los dos para validar la cadena completa\nlet soloNumerosRegex = /^\\d+$/\nsoloNumerosRegex.test(\"12345\")     //true\nsoloNumerosRegex.test(\"123abc\")   //false, tiene letras mezcladas\n\n//ojo: el ^ DENTRO de corchetes no es ancla, ahi significa negacion\nlet noVocalRegex = /[^aeiou]/"}]}, {"numero": 37, "titulo": "Coincidencia Greedy vs Lazy", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Por defecto las regex son greedy (glotonas) — capturan lo mas posible. Con ? despues del cuantificador se vuelven lazy (perezosas) — capturan lo minimo posible."}, {"tipo": "codigo", "codigo": "let html = \"<h1>Titulo</h1>\"\n\n//greedy (por defecto) - llega hasta el ULTIMO caracter que cumpla\nhtml.match(/<.*>/)     //[\"<h1>Titulo</h1>\"] - se paso de largo\n\n//lazy con el ? - se detiene en el PRIMER caracter que cumpla\nhtml.match(/<.*?>/)    //[\"<h1>\"] - esto es lo que yo queria\n\n//el ? despues del cuantificador es lo que cambia el comportamiento"}]}, {"numero": 38, "titulo": "Grupos de Captura ( ) y Reutilizacion", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Los parentesis () crean grupos de captura numerados. Se reusan con \\1, \\2 en la misma regex, o con $1, $2 en .replace()."}, {"tipo": "codigo", "codigo": "//reutilizando lo capturado dentro de la misma regex con \\1\nlet repetidoRegex = /^(\\d+) \\1 \\1$/\nrepetidoRegex.test(\"42 42 42\")   //true, los tres grupos son iguales\nrepetidoRegex.test(\"42 42 43\")   //false, el ultimo no coincide\n\n//reordenando con $1 $2 dentro de replace()\n\"Jose Armando\".replace(/(\\w+)\\s(\\w+)/, \"$2 $1\")\n//resultado: \"Armando Jose\"\n\n//quitando espacios del inicio y del final combinando dos patrones con |\nlet espaciosRegex = /^\\s+|\\s+$/g\n\"   Hola   \".replace(espaciosRegex, \"\")   //\"Hola\""}]}, {"numero": 39, "titulo": "Lookaheads — Aserciones de Anticipacion", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Los lookaheads verifican que algo exista o no exista adelante en la cadena, sin consumir caracteres. Muy utiles para validar contrasenas con multiples condiciones."}, {"tipo": "codigo", "codigo": "//lookahead positivo (?=) - valida que SI venga despues, sin consumirlo\nlet conURegex = /q(?=u)/\nconURegex.test(\"quiero\")   //true, la q esta seguida de u\nconURegex.test(\"qatar\")     //false, no hay u despues\n\n//lookahead negativo (?!) - valida que NO venga despues\nlet sinURegex = /q(?!u)/\nsinURegex.test(\"qatar\")     //true\n\n//combinando dos lookaheads para validar una contrasena\n//necesita 6+ caracteres Y al menos dos numeros seguidos en algun punto\nlet passwordRegex = /(?=\\w{6,})(?=\\D*\\d{2})/\npasswordRegex.test(\"abcd12\")   //true\npasswordRegex.test(\"abc1\")     //false, muy corta y sin dos numeros seguidos"}]}, {"numero": 40, "titulo": "Tabla Resumen de Expresiones Regulares", "bloque": "regex", "contenido": [{"tipo": "tabla", "filas": [["**Patron**", "**Que busca**"], [".", "Cualquier caracter excepto salto de linea"], ["\\w / \\W", "Alfanumerico / No alfanumerico"], ["\\d / \\D", "Digito / No digito"], ["\\s / \\S", "Espacio / No espacio"], ["[abc]", "a, b o c en esa posicion"], ["[^abc]", "Cualquier cosa MENOS a, b o c"], ["[a-z]", "Rango de caracteres"], ["^ / $", "Inicio / Final de cadena"], ["+ / * / ?", "1+, 0+, 0 o 1 repeticiones"], ["{n,m}", "Entre n y m repeticiones"], ["a│b", "a o b (alternativa)"], ["(abc)", "Grupo de captura"], ["\\1 / $1", "Reutilizar grupo 1"], ["(?=...) / (?!...)", "Lookahead positivo / negativo"], [".*  / .*?", "Greedy / Lazy"]]}, {"tipo": "texto", "texto": "La depuracion es el proceso de encontrar y corregir errores en el codigo. JavaScript tiene varios tipos de errores: sintaxis, referencia, tipo y logica. Las herramientas principales son console.log() y typeof."}]}, {"numero": 41, "titulo": "Metodos de Consola", "bloque": "debug", "contenido": [{"tipo": "texto", "texto": "La consola del navegador muestra todos los metodos. freeCodeCamp solo muestra console.log(). Usar estos metodos en puntos estrategicos del codigo ayuda a identificar errores."}, {"tipo": "tabla", "filas": [["**Metodo**", "**Color**", "**Para que sirve**"], ["console.log()", "Blanco", "Imprimir cualquier valor — el mas usado"], ["console.warn()", "Amarillo ⚠️", "Advertencias — algo puede fallar"], ["console.error()", "Rojo ❌", "Errores graves — algo fallo"], ["console.info()", "Azul", "Informacion general"], ["console.table()", "Tabla visual", "Ver arrays u objetos de forma clara"], ["console.time()", "Cronometro", "Medir cuanto tarda una operacion"], ["console.count()", "Contador", "Contar cuantas veces se ejecuta una linea"], ["console.clear()", "Limpia", "Borrar toda la consola"]]}, {"tipo": "codigo", "codigo": "console.log(\"valor:\", miVariable)      //debug general, el mas usado\nconsole.warn(\"cuidado con esto\")        //advertencia, se ve en amarillo\nconsole.error(\"algo salio mal\")         //error, se ve en rojo\nconsole.table(estudiantes)              //muestra un array de objetos como tabla\n\nconsole.time(\"calculoPromedio\")         //inicia el cronometro\n//...codigo que quiero medir...\nconsole.timeEnd(\"calculoPromedio\")      //lo detiene y muestra cuanto tardo\n\nconsole.clear()                          //limpia toda la consola"}]}, {"numero": 42, "titulo": "typeof — Verificar Tipos", "bloque": "debug", "contenido": [{"tipo": "texto", "texto": "typeof devuelve el tipo de dato de una variable como string. Muy util cuando el resultado de una operacion es inesperado — puede ser que los tipos no sean los que crees."}, {"tipo": "codigo", "codigo": "typeof \"hola\"        //\"string\"\ntypeof 42             //\"number\"\ntypeof true           //\"boolean\"\ntypeof undefined      //\"undefined\"\ntypeof null           //\"object\" - esto es un error historico de JS, ojo con esto\ntypeof []             //\"object\" - los arrays tambien son objetos\ntypeof function(){}   //\"function\"\n\n//uso real para encontrar errores silenciosos\nlet calificacion = \"8\"   //esto llego como string, no como number\nconsole.log(typeof calificacion)   //\"string\" - aqui esta el problema\ncalificacion + 2          //\"82\" en vez de 10, se concateno en lugar de sumar"}]}, {"numero": 43, "titulo": "Errores Comunes de Sintaxis", "bloque": "debug", "contenido": [{"tipo": "texto", "texto": "Estos errores impiden que el codigo se ejecute. El navegador o Node los reporta con un mensaje de error especifico."}, {"tipo": "codigo", "codigo": "//1. error de ortografia en el nombre - case sensitive\nlet promedioFinal = 100\nconsole.log(promediofinal)   //ReferenceError, el nombre no es igual\n\n//2. parentesis o llaves sin cerrar\nlet calificaciones = [85, 90, 78   //correccion: le falta el ] de cierre\n\n//3. comillas mezcladas mal\nlet mensaje = 'El estudiante's promedio'   //se cierra en el apostrofe sin querer\nlet mensaje = \"El estudiante's promedio\"    //correccion: comillas dobles por fuera\n\n//4. = en vez de === - el clasico error de comparacion\nif (promedio = 70) { }    //esto ASIGNA 70, no compara, y siempre da true\nif (promedio === 70) { }  //correccion: === para comparar de verdad"}]}, {"numero": 44, "titulo": "Errores Comunes de Logica", "bloque": "debug", "contenido": [{"tipo": "texto", "texto": "Estos errores no detienen el codigo pero producen resultados incorrectos. Son los mas dificiles de encontrar porque no generan mensajes de error."}, {"tipo": "codigo", "codigo": "//1. olvidar los parentesis al llamar la funcion\nfunction calcularPromedio() { return 8 }\n{\n  let resultado = calcularPromedio     //esto guarda la funcion completa, no la ejecuta\n}\n{\n  let resultado = calcularPromedio()   //correccion: con parentesis si la ejecuta\n}\n\n//2. argumentos en el orden incorrecto\nfunction dividir(dividendo, divisor) { return dividendo / divisor }\ndividir(10, 2)   //5 - correcto\ndividir(2, 10)   //0.2 - incorrecto si lo que querias era 10/2\n\n//3. off-by-one, un indice de mas o de menos\nlet calificaciones = [85, 90, 78]\ncalificaciones[calificaciones.length]        //undefined, se paso del rango\ncalificaciones[calificaciones.length - 1]    //78, correccion: el ultimo real\n\n//4. condicion que nunca se cumple = bucle infinito\nfor (let i = 1; i != 10; i += 2) { }   //nunca llega a 10 (1,3,5,7,9,11...)\nfor (let i = 1; i <= 10; i += 2) { }   //correccion: con <= si termina"}]}, {"numero": 45, "titulo": "Estrategia de Depuracion", "bloque": "debug", "contenido": [{"tipo": "texto", "texto": "Cuando el codigo no funciona, sigue este proceso para encontrar el error rapidamente."}, {"tipo": "codigo", "codigo": "//paso 1 - leer el mensaje de error completo, no solo la primera linea\n//ReferenceError -> variable mal escrita o fuera de su alcance\n//TypeError      -> le faltaron los () o el tipo no es el esperado\n//SyntaxError    -> algo sin cerrar, comillas mal puestas, etc\n\n//paso 2 - agregar console.log en los puntos clave para ver que esta pasando\nfunction calcularPromedio(calificaciones) {\n  console.log(\"recibido:\", calificaciones)       //que llego a la funcion\n  console.log(\"tipo:\", typeof calificaciones)     //confirmando el tipo\n  let suma = 0\n  for (let i = 0; i < calificaciones.length; i++) {\n    suma += calificaciones[i]\n  }\n  const promedio = suma / calificaciones.length\n  console.log(\"resultado:\", promedio)              //que esta saliendo al final\n  return promedio\n}\n\n//paso 3 - si esperabas un numero y te esta saliendo texto concatenado,\n//seguramente un valor llego como string y no como number\n\n//paso 4 - revisar las condiciones de los bucles, i < length contra i <= length\n\n//paso 5 - comparar el orden de los argumentos contra como se definio la funcion"}, {"tipo": "texto", "texto": "Los arrays y objetos son las estructuras de datos mas usadas en JavaScript. Los arrays almacenan colecciones ordenadas, los objetos almacenan pares clave-valor. Ambos son mutables y pueden contener cualquier tipo de dato."}]}, {"numero": 46, "titulo": "Metodos de Arrays — Agregar y Eliminar", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "Los arrays tienen metodos para agregar y eliminar elementos en cualquier posicion. Todos modifican el array original excepto slice()."}, {"tipo": "tabla", "filas": [["**Metodo**", "**Donde actua**", "**Retorna**"], ["push(elem)", "Agrega al FINAL", "Nueva longitud del array"], ["pop()", "Elimina del FINAL", "El elemento eliminado"], ["unshift(elem)", "Agrega al INICIO", "Nueva longitud del array"], ["shift()", "Elimina del INICIO", "El elemento eliminado"], ["splice(i, n, ...elems)", "Elimina/agrega en cualquier posicion", "Array con elementos eliminados"], ["slice(inicio, fin)", "Extrae sin modificar el original", "Nuevo array con los elementos"]]}, {"tipo": "codigo", "codigo": "const frutas = [\"manzana\", \"pera\", \"uva\"]\n\nfrutas.push(\"kiwi\")        //[\"manzana\",\"pera\",\"uva\",\"kiwi\"]\nfrutas.pop()                //[\"manzana\",\"pera\",\"uva\"] - y devuelve \"kiwi\"\nfrutas.unshift(\"lechuga\")   //agrega al inicio, ojo que \"lechuga\" no es fruta pero es el ejemplo\nfrutas.shift()               //quita el primero y lo devuelve\n\n//splice(indice, cuantosEliminar, ...loQueAgregas)\nconst posicionUva = frutas.indexOf(\"uva\")\nfrutas.splice(posicionUva, 1)         //elimina uva por su posicion\nfrutas.splice(1, 0, \"mango\", \"kiwi\")  //agrega sin eliminar nada\nfrutas.splice(0, 1, \"manzana\")         //reemplaza 1 elemento por otro\n\n//slice(inicio, fin) - el fin NO se incluye, y no modifica el original\nconst primerasDos = frutas.slice(0, 2)\nconsole.log(frutas)   //el array original queda intacto"}]}, {"numero": 47, "titulo": "Spread Operator con Arrays", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "El operador spread ... permite copiar arrays, combinarlos e insertar elementos en cualquier posicion. Ya visto en ES6 — se aplica igual con arrays."}, {"tipo": "codigo", "codigo": "//copiando un array - queda independiente, no es la misma referencia\nconst frutas = [\"manzana\", \"pera\", \"uva\"]\nconst copiaFrutas = [...frutas]\n\n//combinando dos arrays en uno solo\nconst verduras = [\"zanahoria\", \"brocoli\"]\nconst todo = [...frutas, ...verduras]\n//[\"manzana\",\"pera\",\"uva\",\"zanahoria\",\"brocoli\"]\n\n//usando Object.keys() junto con spread para juntar todo en un array\nconst tienda = { frutas, verduras }\nconst productosDisponibles = [...tienda.frutas, ...tienda.verduras]"}]}, {"numero": 48, "titulo": "indexOf() y Busqueda en Arrays", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "indexOf() busca un elemento en el array y devuelve su posicion. Si no existe devuelve -1. Util para verificar si algo existe antes de operar."}, {"tipo": "codigo", "codigo": "const frutas = [\"manzana\", \"pera\", \"uva\", \"pera\"]\n\nfrutas.indexOf(\"pera\")    //1, la primera aparicion\nfrutas.indexOf(\"mango\")   //-1, no existe en el array\n\n//verificando si algo existe antes de usarlo\nconst posicionUva = frutas.indexOf(\"uva\")\nif (posicionUva !== -1) {\n  console.log(\"La uva si esta en el array\")\n}\n\n//caso real - eliminar algo solo si lo encuentra, si no lo deja igual\nconst eliminarSiExiste = (arr, elemento) => {\n  const posicion = arr.indexOf(elemento)\n  return posicion !== -1 ? arr.splice(posicion, 1) : \"No estaba en el array\"\n}"}]}, {"numero": 49, "titulo": "Arrays Multidimensionales", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "Un array puede contener otros arrays de profundidad arbitraria. Se accede con notacion de corchetes encadenada. Cada nivel requiere un par de corchetes adicional."}, {"tipo": "codigo", "codigo": "//array bidimensional - dos niveles de profundidad\nconst matriz = [[1, 2], [3, 4], [5, 6]]\nmatriz[0][1]   //2 - fila 0, columna 1\nmatriz[2][0]   //5 - fila 2, columna 0\n\n//array con mas niveles todavia\nconst profundo = [[[\"a\"], [\"b\"]], [[\"c\"]]]\nprofundo[0][0][0]   //\"a\"\nprofundo[1][0][0]   //\"c\"\n\n//recorriendo con un for anidado\nfor (let i = 0; i < matriz.length; i++) {\n  for (let j = 0; j < matriz[i].length; j++) {\n    console.log(matriz[i][j])\n  }\n}"}]}, {"numero": 50, "titulo": "Metodos de Objetos", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "Los objetos tienen sus propios metodos para agregar, eliminar, verificar y recorrer propiedades. Las claves no tienen orden garantizado."}, {"tipo": "codigo", "codigo": "const biblioteca = { libros: [], socios: {} }\n\n//agregando socios directamente como objeto\nbiblioteca.socios = {\n  Diego: { nombre: \"Diego\", edad: 16, librosRentados: [] },\n  Danna: { nombre: \"Danna\", edad: 21, librosRentados: [] }\n}\n\n//accediendo con punto y con corchetes\nbiblioteca.socios.Diego.edad          //16\nbiblioteca.socios[\"Diego\"][\"edad\"]    //lo mismo, con corchetes\n\n//verificando que una propiedad exista antes de usarla\nbiblioteca.socios.hasOwnProperty(\"Diego\")   //true\n\n//recorriendo todas las claves de un objeto con for...in\nfor (const clave in biblioteca.socios) {\n  console.log(`Socio: ${clave} | Edad: ${biblioteca.socios[clave].edad}`)\n}"}]}, {"numero": 51, "titulo": "for...in vs for normal", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "El for...in recorre las claves de un objeto. El for normal recorre indices de un array. Cada uno es la herramienta correcta para su estructura."}, {"tipo": "codigo", "codigo": "//for normal - cuando necesitas el indice, ideal para arrays\nconst libros = [\"Clean Code\", \"Eloquent JS\", \"You Dont Know JS\"]\nfor (let i = 0; i < libros.length; i++) {\n  console.log(i, libros[i])   //0 \"Clean Code\", 1 \"Eloquent JS\"...\n}\n\n//for...in - cuando necesitas las claves, ideal para objetos\nconst socios = { Diego: 16, Danna: 21, Melany: 24 }\nfor (const clave in socios) {\n  console.log(clave, socios[clave])   //Diego 16, Danna 21...\n}\n\n//caso real - filtrar solo los libros disponibles con un for normal\nconst librosDisponibles = []\nfor (let i = 0; i < libros.length; i++) {\n  if (libros[i].disponible === true) {\n    librosDisponibles.push(libros[i])\n  }\n}"}, {"tipo": "texto", "texto": "*Este bloque aplica todo lo aprendido hasta ahora para resolver 16 problemas reales. No hay teoria de golpe — cada ejercicio introduce herramientas cuando las necesitas. El enfoque es: dividir el problema, identificar las herramientas correctas y combinarlas.*"}]}, {"numero": 52, "titulo": "split() y join() — Dividir y Unir Strings", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "split() convierte un string en array usando un separador. join() hace lo inverso: une los elementos de un array en un string. Son el duo estandar cuando necesitas procesar palabras individuales de una frase."}, {"tipo": "codigo", "codigo": "//split(separador) - convierte un string en array\n\"hola mundo\".split(\" \")    //[\"hola\", \"mundo\"]\n\"a,b,c\".split(\",\")          //[\"a\", \"b\", \"c\"]\n\"hola\".split(\"\")             //[\"h\",\"o\",\"l\",\"a\"] - caracter por caracter\n\n//join(separador) - convierte un array de vuelta a string\n[\"hola\", \"mundo\"].join(\" \")   //\"hola mundo\"\n[\"a\",\"b\",\"c\"].join(\"-\")        //\"a-b-c\"\n\n//ojo, join() no modifica el array, hay que guardar el resultado\nconst resultado = arr.join(\" \")   //correcto\narr.join(\" \")                       //el resultado se pierde si no lo guardas\n\n//patron clasico que use varias veces: split, proceso cada palabra, join\nconst tituloCapitalizado = (str) => {\n  const palabras = str.split(\" \")\n  const procesado = palabras.map(palabra =>\n    palabra[0].toUpperCase() + palabra.slice(1).toLowerCase()\n  )\n  return procesado.join(\" \")\n}"}]}, {"numero": 53, "titulo": "charAt(), toUpperCase() y toLowerCase()", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "Metodos para transformar el casing de strings. charAt(n) accede al caracter en la posicion n — equivalente a str[n] pero mas explicito. Muy usados juntos para capitalizar palabras."}, {"tipo": "codigo", "codigo": "//charAt(n) hace lo mismo que str[n]\n\"hello\".charAt(0)   //\"h\"\n\"hello\"[0]           //\"h\" - las dos formas funcionan igual\n\n//toUpperCase() y toLowerCase()\n\"hello\".toUpperCase()   //\"HELLO\"\n\"WORLD\".toLowerCase()   //\"world\"\n\n//el patron que uso siempre para capitalizar una palabra\nconst capitalizar = (palabra) => {\n  const primeraLetra = palabra[0].toUpperCase()\n  const restoLetras = palabra.slice(1).toLowerCase()\n  return primeraLetra + restoLetras\n}\ncapitalizar(\"hOLA\")   //\"Hola\""}]}, {"numero": 54, "titulo": "includes() — Verificar si algo existe", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "includes() devuelve true si el elemento o subcadena existe, false si no. Funciona en strings (busca texto) y en arrays (busca elementos). A diferencia de indexOf(), devuelve booleano directamente."}, {"tipo": "codigo", "codigo": "//en strings, busca si una parte esta contenida\n\"hola mundo\".includes(\"mundo\")   //true\n\"hola mundo\".includes(\"xyz\")      //false\n\n//en arrays, busca si un elemento existe\n[1, 2, 3].includes(2)   //true\n[1, 2, 3].includes(9)   //false\n\n//antes usaba indexOf, includes es mas legible\narr.indexOf(\"x\") !== -1   //forma antigua\narr.includes(\"x\")          //forma moderna, se entiende mejor\n\n//caso real, verificando letra por letra si una palabra contiene otra\nconst contieneTodasLasLetras = (palabra1, palabra2) => {\n  for (let i = 0; i < palabra2.length; i++) {\n    if (!palabra1.includes(palabra2[i])) return false\n  }\n  return true\n}"}]}, {"numero": 55, "titulo": "Math.max() y Math.min() con Spread", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "Math.max() y Math.min() reciben numeros separados por comas, no un array. El spread operator (...) expande el array en argumentos individuales, haciendo que funcionen juntos."}, {"tipo": "codigo", "codigo": "//con valores sueltos funciona directo\nMath.max(1, 5, 3)   //5\nMath.min(1, 5, 3)   //1\n\n//con un array directo NO funciona\nMath.max([1, 5, 3])   //NaN\n\n//con spread se expande el array como si fueran argumentos sueltos\nconst numeros = [1, 5, 3]\nMath.max(...numeros)   //5\n\n//caso real, sacando el mayor de cada sub-array\nconst mayoresDeCadaGrupo = (arr) => {\n  return arr.map(grupo => Math.max(...grupo))\n}\nmayoresDeCadaGrupo([[4,5,1,3],[13,27,18,26]])   //[5, 27]"}]}, {"numero": 56, "titulo": "sort() con Comparador Numerico", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "sort() sin argumentos ordena como texto (1, 10, 2...). Para ordenar numeros correctamente se necesita una funcion comparadora. El comparador (a, b) => a - b ordena de menor a mayor."}, {"tipo": "codigo", "codigo": "//sin comparador, sort() ordena como si fuera texto - esto sale mal con numeros\n[10, 1, 21, 2].sort()   //[1, 10, 2, 21] - incorrecto\n\n//con comparador numerico si funciona bien\n[10, 1, 21, 2].sort((a, b) => a - b)   //[1, 2, 10, 21] ascendente\n[10, 1, 21, 2].sort((a, b) => b - a)   //[21, 10, 2, 1] descendente\n\n//como pensar la logica del comparador:\n//a - b menor que 0  -> a va primero\n//a - b mayor que 0  -> b va primero\n\n//caso real, ordenar y despues buscar en que posicion entraria un numero\nconst indiceParaInsertar = (arr, numero) => {\n  arr.sort((a, b) => a - b)\n  for (let i = 0; i < arr.length; i++) {\n    if (arr[i] >= numero) return i\n  }\n  return arr.length   //si es mayor que todos, va al final\n}\nindiceParaInsertar([40, 60], 50)   //1"}]}, {"numero": 57, "titulo": "typeof — Operador, no Metodo", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "typeof ya estaba en tus apuntes como tip, pero en este bloque se usa directamente para resolver ejercicios. El error comun es usarlo como propiedad (valor.typeof) cuando en realidad es un operador que va ANTES del valor."}, {"tipo": "codigo", "codigo": "//typeof va ANTES del valor, es operador, no un metodo\ntypeof \"hola\"        //\"string\"\ntypeof 42             //\"number\"\ntypeof true           //\"boolean\"\ntypeof null           //\"object\" - comportamiento raro pero asi es JS\ntypeof []             //\"object\" - los arrays tambien son objetos\n\n//error comun que yo cometi al principio - usarlo como si fuera propiedad\nvariable.typeof      //ERROR, esto no existe\ntypeof variable        //correcto\n\n//siempre devuelve un string, hay que comparar con comillas\ntypeof variable == \"boolean\"    //correcto\ntypeof variable == boolean       //ERROR, boolean sin comillas no existe\n\n//uso real validando el tipo antes de procesar algo\nconst esBooleano = (valor) => typeof valor === \"boolean\""}]}, {"numero": 58, "titulo": "Boolean() y Valores Falsy", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "JavaScript tiene 6 valores falsy — todo lo demas es truthy. Boolean() convierte cualquier valor a su equivalente booleano. Util para filtrar valores no deseados de arrays."}, {"tipo": "tabla", "filas": [["**Valor Falsy**", "**Por que es falso**"], ["false", "El booleano falso"], ["0", "El numero cero"], ["\"\"  (string vacio)", "String sin contenido"], ["null", "Ausencia intencional de valor"], ["undefined", "Variable declarada sin valor"], ["NaN", "Not a Number — resultado de operacion invalida"]]}, {"tipo": "codigo", "codigo": "//Boolean() convierte cualquier cosa a true o false\nBoolean(0)            //false\nBoolean(\"\")            //false\nBoolean(null)          //false\nBoolean(undefined)    //false\nBoolean(NaN)            //false\n\nBoolean(1)             //true\nBoolean(\"hola\")        //true\nBoolean([])             //true - un array vacio SI es truthy, esto me confundio al inicio\nBoolean({})              //true - un objeto vacio tambien\n\n//tres formas equivalentes, la ultima es la que mas uso\nif (Boolean(valor) === true) { }\nif (Boolean(valor)) { }\nif (valor) { }   //la mas corta, JS ya evalua truthy/falsy solo\n\n//caso real, filtrando los valores falsy de un array\nconst quitarFalsy = (arr) => {\n  const resultado = []\n  for (let i = 0; i < arr.length; i++) {\n    if (Boolean(arr[i])) resultado.push(arr[i])\n  }\n  return resultado\n}\nquitarFalsy([7, \"ate\", \"\", false, 9])   //[7, \"ate\", 9]\n\n//la forma corta que descubri despues, hace exactamente lo mismo\nconst quitarFalsyCorto = (arr) => arr.filter(Boolean)"}]}, {"numero": 59, "titulo": "Callbacks — Funciones como Argumentos", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "Una funcion puede recibir otra funcion como argumento. Esa funcion se llama callback. No defines que evalua — solo la ejecutas pasandole el elemento actual. Es la base de metodos como filter(), map() y forEach() que vienen mas adelante."}, {"tipo": "codigo", "codigo": "//una funcion que recibe otra funcion como argumento\nconst buscarElemento = (arr, condicion) => {\n  for (let i = 0; i < arr.length; i++) {\n    if (condicion(arr[i])) return arr[i]   //ejecutando la funcion que me pasaron\n  }\n  return undefined\n}\n\n//al llamarla, la logica se manda como argumento (el callback)\nbuscarElemento([1, 3, 5, 8], function(numero) { return numero % 2 === 0 })\n//devuelve 8, el primer numero par\n\n//con arrow function queda mas corto, mismo resultado\nbuscarElemento([1, 3, 5, 8], numero => numero % 2 === 0)\n\n//el callback puede ser cualquier condicion que se me ocurra\nbuscarElemento([1, 3, 5, 8], numero => numero > 4)   //devuelve 5\n\n//a buscarElemento no le importa que evalua el callback,\n//solo lo ejecuta y revisa si devuelve true o false"}]}, {"numero": 60, "titulo": "Patrones Algoritmicos Esenciales", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "Estos patrones aparecieron en varios ejercicios del bloque. Reconocerlos te permite atacar problemas nuevos mas rapido porque ya sabes que herramientas combinar."}, {"tipo": "codigo", "codigo": "//patron 1: variable acumuladora\nlet resultado = \"\"\nfor (let i = str.length - 1; i >= 0; i--) {\n  resultado += str[i]\n}\n\n//patron 2: variable de maximo\nlet maximo = 0\nfor (let i = 0; i < arr.length; i++) {\n  if (arr[i].length > maximo) maximo = arr[i].length\n}\n\n//patron 3: split, procesar, join\nconst palabras = str.split(\" \")\n//...proceso cada palabra con map...\nconst final = palabras.join(\" \")\n\n//patron 4: copiar el array antes de mutarlo\nconst copia = [...arrOriginal]        //con spread\nconst copia2 = arrOriginal.slice()    //con slice sin argumentos\n\n//patron 5: bucle con saltos, avanzando de \"size\" en \"size\"\nfor (let i = 0; i < arr.length; i += size) {\n  resultado.push(arr.slice(i, i + size))\n}\n\n//patron 6: ordenar y despues buscar la posicion\narr.sort((a, b) => a - b)\nfor (let i = 0; i < arr.length; i++) {\n  if (arr[i] >= numero) return i\n}"}, {"tipo": "texto", "texto": "Programacion Orientada a Objetos"}, {"tipo": "texto", "texto": "*Este bloque explica como JavaScript organiza y reutiliza codigo mediante objetos, herencia y encapsulamiento. Es la base de como estan construidos los frameworks, librerias y sistemas reales que usamos todos los dias.*"}]}, {"numero": 61, "titulo": "La Palabra Clave this", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "this siempre se refiere al objeto que esta ejecutando el metodo. Sin this, un metodo tendria que usar el nombre de la variable directamente — si renombras el objeto, todo el codigo que lo referencia se rompe. Con this, el metodo siempre apunta al objeto correcto sin importar como se llame."}, {"tipo": "codigo", "codigo": "{\n  let articulo = {\n    titulo: \"Noticia del dia\",\n\n    //sin this - fragil, depende de que la variable se siga llamando \"articulo\"\n    mostrarTitulo: function() { return \"Titulo: \" + articulo.titulo }\n  }\n}\n\n{\n  let articulo = {\n    titulo: \"Noticia del dia\",\n\n    //con this - reutilizable, ya no depende del nombre de la variable\n    mostrarTitulo: function() { return \"Titulo: \" + this.titulo }\n  }\n\n  //this dentro de un metodo apunta al objeto que lo esta llamando\n  articulo.mostrarTitulo()   //\"Titulo: Noticia del dia\"\n}"}]}, {"numero": 62, "titulo": "Constructores — La Forma Clasica (Pre-ES6)", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Antes de ES6 y las clases, los objetos se creaban con funciones constructoras. El nombre va en PascalCase para distinguirlos de funciones normales. Internamente es lo mismo que class — ES6 solo agrego una sintaxis mas limpia encima."}, {"tipo": "codigo", "codigo": "//forma clasica - function constructor, antes de ES6\n{\n  function Empleado(nombre, puesto) {\n    this.nombre = nombre   //propiedad propia\n    this.puesto = puesto   //propiedad propia\n  }\n}\n\n//forma moderna con class - mismo resultado, distinta sintaxis\n{\n  class Empleado {\n    constructor(nombre, puesto) {\n      this.nombre = nombre\n      this.puesto = puesto\n    }\n  }\n}\n\n//convenciones que segui:\n//1. el nombre del constructor en Mayuscula (Empleado, no empleado)\n//2. this para asignar las propiedades\n//3. no lleva return, el objeto se crea solo con new"}]}, {"numero": 63, "titulo": "new e Instancias", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "El operador new crea un nuevo objeto a partir del constructor. Sin new, this no apunta al nuevo objeto y el resultado es incorrecto. Cada objeto creado con new es una instancia independiente con sus propias propiedades."}, {"tipo": "codigo", "codigo": "function Vehiculo(marca, modelo) {\n  this.marca = marca\n  this.modelo = modelo\n  this.ruedas = 4\n}\n\n//new crea una instancia nueva cada vez\nlet auto1 = new Vehiculo(\"Toyota\", \"Corolla\")\nlet auto2 = new Vehiculo(\"Honda\", \"Civic\")\n\n//cada instancia tiene su propia copia de las propiedades\nauto1.marca   //\"Toyota\"\nauto2.marca   //\"Honda\"\n\n//modificar una no afecta a la otra\nauto1.marca = \"Nissan\"\nauto2.marca   //sigue siendo \"Honda\", sin cambios"}]}, {"numero": 64, "titulo": "instanceof y Propiedad constructor", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "instanceof verifica si un objeto fue creado con un constructor especifico. La propiedad constructor apunta a la funcion que creo el objeto. instanceof es mas confiable porque la propiedad constructor puede ser sobreescrita accidentalmente."}, {"tipo": "codigo", "codigo": "function Vehiculo() {}\nlet auto = new Vehiculo()\n\n//instanceof pregunta desde el objeto\nauto instanceof Vehiculo   //true\nauto instanceof Object      //true - todo en JS hereda de Object\n\n//la propiedad constructor apunta a quien lo creo\nauto.constructor === Vehiculo   //true\nauto.constructor === Object      //false\n\n//uso real - verificar el tipo antes de procesarlo\nconst esVehiculo = (candidato) => candidato instanceof Vehiculo"}]}, {"numero": 65, "titulo": "Propiedades Propias vs Prototype", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Las propiedades propias viven dentro de cada instancia — cada objeto carga su copia. Las propiedades de prototype viven en un lugar compartido — todos los objetos acceden a la misma. En produccion, los metodos van en prototype para no duplicar codigo en memoria."}, {"tipo": "codigo", "codigo": "function Empleado(nombre) {\n  this.nombre = nombre   //propiedad propia - cada empleado tiene la suya\n}\n\n//metodo en prototype - una sola copia compartida entre todas las instancias\nEmpleado.prototype.saludar = function() {\n  console.log(this.nombre + \" dice hola\")\n}\n\nlet empleado1 = new Empleado(\"Ana\")\n\n//propiedad propia - aparece en el objeto\nconsole.log(empleado1)              //{ nombre: \"Ana\" }\nempleado1.hasOwnProperty(\"nombre\")   //true\n\n//propiedad de prototype - no aparece en el objeto pero si es accesible\nempleado1.saludar()                     //funciona, \"Ana dice hola\"\nempleado1.hasOwnProperty(\"saludar\")     //false, esta en prototype no en el objeto\n\n//sin prototype: 1000 empleados = 1000 copias de saludar()\n//con prototype: 1000 empleados = 1 sola copia compartida"}]}, {"numero": 66, "titulo": "Iterar y Clasificar Propiedades", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "for...in recorre TODAS las propiedades accesibles — propias y de prototype. hasOwnProperty permite clasificarlas: si retorna true es propia, si retorna false es del prototype."}, {"tipo": "codigo", "codigo": "function Empleado(nombre) { this.nombre = nombre }\nEmpleado.prototype.puesto = \"Sin asignar\"\n\nlet empleado1 = new Empleado(\"Ana\")\n\nconst propiasProp = []\nconst prototypeProp = []\n\nfor (const propiedad in empleado1) {\n  if (empleado1.hasOwnProperty(propiedad)) {\n    propiasProp.push(propiedad)      //[\"nombre\"]\n  } else {\n    prototypeProp.push(propiedad)    //[\"puesto\"]\n  }\n}\n\n//propiasProp    = [\"nombre\"]  - vive en el objeto\n//prototypeProp  = [\"puesto\"]  - vive en Empleado.prototype"}]}, {"numero": 67, "titulo": "Asignar Objeto Completo al Prototype", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "En vez de agregar propiedades al prototype una por una, puedes asignarle un objeto completo. IMPORTANTE: esto borra la propiedad constructor — siempre hay que redeclararla manualmente."}, {"tipo": "codigo", "codigo": "//forma lenta - una por una\nEmpleado.prototype.puesto = \"General\"\nEmpleado.prototype.saludar = function() { console.log(\"hola\") }\nEmpleado.prototype.despedirse = function() { console.log(\"adios\") }\n\n//forma rapida - todo el objeto de una vez\nEmpleado.prototype = {\n  constructor: Empleado,   //obligatorio, se borra al reasignar el prototype\n  puesto: \"General\",\n  saludar: function() { console.log(\"hola\") },\n  despedirse: function() { console.log(\"adios\") }\n}\n\n//si olvido poner constructor: Empleado\nlet empleado1 = new Empleado(\"Ana\")\nempleado1.constructor === Empleado   //false - esto es un problema\nempleado1.constructor === Object      //true - incorrecto\n\n//con constructor: Empleado ya declarado, queda correcto\nempleado1.constructor === Empleado   //true"}]}, {"numero": 68, "titulo": "Cadena de Prototipos", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Todo objeto en JavaScript tiene un prototype. El prototype a su vez tiene su propio prototype. Esto forma una cadena. Cuando buscas una propiedad, JavaScript sube por la cadena hasta encontrarla o llegar a null. Por eso hasOwnProperty, toString y otros metodos funcionan en cualquier objeto sin haberlos definido."}, {"tipo": "codigo", "codigo": "//la cadena completa para un empleado:\n//empleado1\n//  -> Empleado.prototype   (saludar, despedirse - metodos propios)\n//    -> Object.prototype   (hasOwnProperty, toString...)\n//      -> null             (aqui termina la cadena)\n\n//verificando la cadena con isPrototypeOf\nEmpleado.prototype.isPrototypeOf(empleado1)          //true\nObject.prototype.isPrototypeOf(Empleado.prototype)   //true\n\n//por eso esto funciona sin que yo lo defina\nempleado1.hasOwnProperty(\"nombre\")   //viene heredado de Object.prototype\nempleado1.toString()                    //tambien viene de ahi\n\n//cuando llamo empleado1.saludar():\n//1. busca en empleado1          - no esta\n//2. busca en Empleado.prototype - lo encuentra, lo ejecuta\n//cuando llamo empleado1.hasOwnProperty():\n//1. busca en empleado1          - no esta\n//2. busca en Empleado.prototype - tampoco esta\n//3. busca en Object.prototype   - lo encuentra ahi"}]}, {"numero": 69, "titulo": "Herencia — Object.create() y Supertipos", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Cuando varios constructores comparten metodos, se crea un padre (supertipo) con lo comun. Object.create(Parent.prototype) conecta el hijo al padre. Siempre hay que reparar el constructor despues de la conexion."}, {"tipo": "codigo", "codigo": "//PADRE - supertipo con el comportamiento comun\nfunction Animal() {}\nAnimal.prototype = {\n  constructor: Animal,\n  comer: function() { console.log(\"comiendo\") },\n  dormir: function() { console.log(\"durmiendo\") }\n}\n\n//HIJO - hereda de Animal\nfunction Perro(nombre) {\n  this.nombre = nombre\n}\n\n//1. conectar el hijo con el padre\nPerro.prototype = Object.create(Animal.prototype)\n\n//2. reparar el constructor, se borra al hacer Object.create\nPerro.prototype.constructor = Perro\n\n//3. agregar los metodos propios del hijo\nPerro.prototype.ladrar = function() { console.log(\"guau!\") }\n\n//resultado, el perro ya tiene todo\nlet rex = new Perro(\"Rex\")\nrex.comer()    //heredado de Animal\nrex.ladrar()   //propio de Perro\n\nrex instanceof Perro    //true\nrex instanceof Animal   //true - tambien es un Animal"}]}, {"numero": 70, "titulo": "Sobreescribir Metodos Heredados", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Un hijo puede redefinir un metodo heredado del padre. JavaScript usa el primero que encuentra en la cadena — si el hijo lo tiene, nunca llega al padre. Util cuando el comportamiento general no aplica para un caso especifico."}, {"tipo": "codigo", "codigo": "function Animal() {}\nAnimal.prototype.describir = function() {\n  return \"Soy un animal\"\n}\n\nfunction Pinguino() {}\nPinguino.prototype = Object.create(Animal.prototype)\nPinguino.prototype.constructor = Pinguino\n\n//sobreescribiendo - mismo nombre de metodo, comportamiento diferente\nPinguino.prototype.describir = function() {\n  return \"Soy un pinguino, no puedo volar\"\n}\n\nlet skipper = new Pinguino()\nskipper.describir()   //\"Soy un pinguino, no puedo volar\"\n//JavaScript encuentra describir() en Pinguino.prototype primero\n//y ahi se detiene, nunca llega hasta Animal.prototype\n\n//orden de busqueda:\n//1. skipper propio       - no tiene describir\n//2. Pinguino.prototype   - lo encuentra aqui, se detiene\n//3. Animal.prototype     - nunca llega a revisarlo"}]}, {"numero": 71, "titulo": "Mixins — Compartir entre Objetos No Relacionados", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "La herencia conecta objetos con relacion familiar. Los mixins comparten habilidades entre objetos sin relacion. Un Ave y un Avion no son familia pero ambos pueden volar. En produccion: exportarPDF, registrarAuditoria, enviarNotificacion — habilidades que muchos tipos necesitan."}, {"tipo": "codigo", "codigo": "//mixin - una funcion que le agrega metodos a cualquier objeto\nconst volarMixin = function(obj) {\n  obj.volar = function() { console.log(\"volando!\") }\n}\n\nlet ave = { nombre: \"Aguila\", patas: 2 }\nlet avion = { modelo: \"737\", motores: 2 }\n\n//los dos reciben la habilidad sin tener relacion de herencia entre ellos\nvolarMixin(ave)\nvolarMixin(avion)\n\nave.volar()    //\"volando!\"\navion.volar()  //\"volando!\"\n\n//caso real - exportarPDF lo necesitan Empleado, Reporte y Factura\n//no tienen relacion entre si pero comparten esa habilidad\nconst exportarMixin = function(obj) {\n  obj.exportarPDF = function() {\n    return \"Exportando \" + JSON.stringify(this)\n  }\n}"}]}, {"numero": 72, "titulo": "Closures — Propiedades Privadas", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Una variable declarada con let dentro del constructor es privada — nada fuera puede accederla directamente. Solo los metodos definidos en el mismo contexto pueden leerla. En produccion: contrasenas, saldos, tokens — datos que no deben exponerse al exterior."}, {"tipo": "codigo", "codigo": "function CuentaBancaria(saldoInicial) {\n  //variable privada - nadie desde afuera la puede modificar directamente\n  let _saldo = saldoInicial\n\n  //metodos privilegiados - son el unico acceso al saldo\n  this.getSaldo = function() { return _saldo }\n  this.depositar = function(monto) { _saldo += monto }\n  this.retirar = function(monto) {\n    if (monto > _saldo) return \"Saldo insuficiente\"\n    _saldo -= monto\n  }\n}\n\nlet cuenta = new CuentaBancaria(1000)\n\ncuenta.getSaldo()      //1000, accediendo por la \"ventanilla\"\ncuenta.depositar(500)  //el saldo interno ahora es 1500\ncuenta._saldo           //undefined, no existe para afuera\ncuenta._saldo = 99999   //no tiene ningun efecto, el saldo real sigue en 1500\n\n//el closure hace que getSaldo y depositar \"recuerden\" el contexto\n//donde nacieron, por eso pueden acceder a _saldo aunque nadie mas pueda"}]}, {"numero": 73, "titulo": "IIFE y Modulos", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Una IIFE (Immediately Invoked Function Expression) se declara y ejecuta al instante. Combinada con un objeto de retorno forma un modulo — agrupa funcionalidad relacionada sin contaminar el scope global. Asi estan construidas librerias como jQuery, Lodash y los sistemas internos de frameworks como React."}, {"tipo": "codigo", "codigo": "//IIFE basica - se ejecuta sola en el momento\n(function() {\n  console.log(\"esto se ejecuta al instante\")\n})()\n\n//modulo con IIFE - agrupa varias funciones relacionadas\nlet ModuloPagos = (function() {\n  //variable privada del modulo\n  let _tasaImpuesto = 0.16\n\n  //solo esto queda visible desde afuera\n  return {\n    calcularTotal: function(precio) {\n      return precio + (precio * _tasaImpuesto)\n    },\n    pagarConTarjeta: function(obj) {\n      obj.pagar = function(monto) {\n        console.log(\"Tarjeta: $\" + monto)\n      }\n    }\n  }\n})()\n\n//uso desde afuera\nModuloPagos.calcularTotal(100)   //116\nModuloPagos._tasaImpuesto         //undefined, es privada\n\nlet orden = {}\nModuloPagos.pagarConTarjeta(orden)\norden.pagar(500)   //\"Tarjeta: $500\""}]}, {"numero": 74, "titulo": "Leccion Practica — Function.call() para Herencia Clasica", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Durante el examen de POO, en lugar de usar super(), se investigo Function.call() — la forma nativa de reutilizar el constructor del padre en la sintaxis clasica (sin class). Es importante reconocerla porque es lo que ocurre detras de escena cuando usas super() en una clase."}, {"tipo": "codigo", "codigo": "//el problema: Auto necesita las mismas propiedades que Vehiculo\nfunction Vehiculo(marca, modelo, kilometraje) {\n  this.marca = marca\n  this.modelo = modelo\n  this.kilometraje = kilometraje\n}\n\n//sin Function.call() tendria que repetir todo otra vez\n{\n  function Auto(marca, modelo, kilometraje, numPuertas) {\n    this.marca = marca              //duplicado\n    this.modelo = modelo            //duplicado\n    this.kilometraje = kilometraje  //duplicado\n    this.numPuertas = numPuertas\n  }\n}\n\n//con Function.call() reutilizo el constructor del padre\n{\n  function Auto(marca, modelo, kilometraje, numPuertas) {\n    Vehiculo.call(this, marca, modelo, kilometraje)\n    //el this de Auto se convierte en el contexto de Vehiculo,\n    //asi Vehiculo asigna sus propiedades directo en el Auto\n    this.numPuertas = numPuertas   //solo agrego lo que es nuevo\n  }\n}\n\n//el equivalente moderno seria con class y super()\n{\n  class Auto extends Vehiculo {\n    constructor(marca, modelo, kilometraje, numPuertas) {\n      super(marca, modelo, kilometraje)   //super() es lo mismo que Vehiculo.call(this,...)\n      this.numPuertas = numPuertas\n    }\n  }\n}\n\n//Function.call(contexto, arg1, arg2...)\n//el primer argumento siempre es el \"this\" que va a usar la funcion llamada"}]}, {"numero": 75, "titulo": "Leccion Practica — Valor Congelado en Modulos IIFE", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Un modulo IIFE se ejecuta UNA SOLA VEZ en el momento en que el codigo la encuentra. Si guardas un valor dentro del modulo al crearlo, ese valor queda congelado — no se recalcula automaticamente despues. Esto fue descubierto durante el examen de POO al intentar que ReporteModule reflejara las ordenes agregadas despues de su creacion."}, {"tipo": "codigo", "codigo": "const taller = { ordenes: [] }\n\n//el problema - el valor queda congelado en el momento en que se crea el modulo\n{\n  const ReporteModule = (function() {\n    let _totalOrdenes = taller.ordenes.length   //lee 0 justo al crearse\n    return {\n      generarReporte: function() {\n        return \"Ordenes: \" + _totalOrdenes   //siempre va a devolver 0\n      }\n    }\n  })()\n\n  taller.ordenes.push({ servicio: \"afinacion\" })   //agrego una orden\n  ReporteModule.generarReporte()   //\"Ordenes: 0\" - sigue congelado, esto no es lo que quiero\n}\n\n//la solucion - leer el valor real en el momento de llamar el metodo\n{\n  const ReporteModule = (function() {\n    return {\n      generarReporte: function() {\n        return \"Ordenes: \" + taller.ordenes.length   //recalcula cada vez que se llama\n      }\n    }\n  })()\n\n  taller.ordenes.push({ servicio: \"afinacion\" })\n  ReporteModule.generarReporte()   //\"Ordenes: 1\" - ahora si es correcto\n}\n\n//la regla que me quedo clara: si un valor puede cambiar despues\n//de crear el modulo, hay que calcularlo dentro del metodo, no al inicio"}, {"tipo": "texto", "texto": "Programacion Funcional"}, {"tipo": "texto", "texto": "*La programacion funcional es un estilo de escribir codigo donde las funciones son puras, no modifican nada externo y siempre producen el mismo resultado para los mismos argumentos. No introduce mucha sintaxis nueva — cambia la forma de pensar: en vez de mutar datos, transformas y creas cosas nuevas.*"}]}, {"numero": 76, "titulo": "Principios de Programacion Funcional", "bloque": "funcional", "contenido": [{"tipo": "texto", "texto": "Tres principios fundamentales que guian el estilo funcional. Seguirlos hace el codigo mas predecible, mas facil de testear y menos propenso a bugs."}, {"tipo": "codigo", "codigo": "//principio 1: funciones puras - misma entrada, mismo resultado siempre\nconst sumar = (a, b) => a + b   //pura, no depende de nada de afuera\n\nlet total = 0\nconst sumarImpura = (n) => { total += n; return total }   //impura, depende de total\n\n//principio 2: no mutar - nunca modificar los datos originales\nconst numeros = [1, 2, 3]\n\nnumeros.push(4)                    //MAL - muta el array directamente\nconst nuevoArr = numeros.concat([4])   //BIEN - crea un array nuevo\nconst nuevoArr2 = [...numeros, 4]       //BIEN - el spread tambien crea uno nuevo\n\n//principio 3: dependencias explicitas - todo lo que la funcion necesita\n//debe entrar como argumento, no leerse de una variable externa\nlet impuesto = 0.16\n\nconst calcularImpura = (precio) => precio * impuesto   //depende de una variable externa, fragil\n\nconst calcularPura = (precio, tasa) => precio * tasa    //todo entra como argumento, predecible\ncalcularPura(100, 0.16)   //16"}]}, {"numero": 77, "titulo": "Terminologia — Callbacks, Primera Clase, Orden Superior, Lambdas", "bloque": "funcional", "contenido": [{"tipo": "texto", "texto": "Cuatro terminos que describen como se comportan las funciones en JavaScript. En la practica suelen referirse a la misma funcion — el nombre depende del rol que cumple en ese momento."}, {"tipo": "codigo", "codigo": "//funciones de primera clase\n//en JS las funciones son valores como cualquier otro, se pueden guardar y pasar\nconst saludar = function() { return \"hola\" }   //guardada en una variable\n\n//funciones de orden superior\n//reciben una funcion como argumento, o devuelven otra funcion\nconst ejecutar = (fn) => fn()   //recibe fn como argumento\nejecutar(saludar)   //\"hola\"\n\n//callbacks\n//la funcion que se le pasa a otra para que la ejecute cuando decida\nejecutar(saludar)\n//     saludar aqui es el callback, ejecutar decide cuando llamarla\n\n//ya los uso todo el tiempo con filter, map, forEach\n[1, 2, 3].filter(numero => numero > 1)   //numero => numero > 1 es el callback\n\n//lambdas\n//nombre generico para funciones que viajan como valor, sea callback o no\nconst doble = numero => numero * 2   //lambda, funcion anonima usada como valor\n\n//resumen: la misma funcion cambia de nombre segun el rol que este cumpliendo\n//primera clase  -> se puede usar como valor\n//orden superior -> la funcion que la recibe\n//callback       -> la que otra funcion decide ejecutar\n//lambda         -> funcion anonima que viaja como valor"}]}, {"numero": 78, "titulo": "concat() — Alternativa No Mutante a push()", "bloque": "funcional", "contenido": [{"tipo": "texto", "texto": "concat() une arrays y devuelve uno NUEVO sin modificar los originales. Es la alternativa funcional a push(), que muta el array original. Tambien funciona para agregar elementos individuales."}, {"tipo": "codigo", "codigo": "//push muta el array original\nconst numeros = [1, 2, 3]\nnumeros.push(4)   //numeros ahora es [1,2,3,4], se modifico\n\n//concat devuelve un array nuevo, el original queda intacto\nconst numeros2 = [1, 2, 3]\nconst conCuatro = numeros2.concat([4])   //conCuatro = [1,2,3,4]\nconsole.log(numeros2)   //[1,2,3] - sin cambios\n\n//tambien sirve para unir dos arrays completos\n[1, 2].concat([3, 4])   //[1,2,3,4]\n\n//o para agregar un elemento suelto\n[1, 2].concat(3)   //[1,2,3]\n\n//el spread hace exactamente lo mismo\nconst conCuatroSpread = [...numeros2, 4]   //[1,2,3,4]\n\n//regla que aprendi: si necesito agregar algo sin mutar el original,\n//uso concat() o spread en vez de push()"}]}, {"numero": 79, "titulo": "Convertir Strings a Numeros", "bloque": "funcional", "contenido": [{"tipo": "texto", "texto": "Cuando los datos llegan como strings (ej: de una API o un objeto JSON), hay que convertirlos a numero antes de hacer calculos matematicos. Hay tres formas — el operador + es el mas compacto dentro de callbacks."}, {"tipo": "codigo", "codigo": "//forma 1: Number() - explicita y facil de leer\nNumber(\"42\")     //42\nNumber(\"3.14\")   //3.14\nNumber(\"\")        //0\nNumber(\"hola\")    //NaN\n\n//forma 2: parseFloat() - para cuando espero decimales\nparseFloat(\"3.14\")   //3.14\nparseFloat(\"3.99\")   //3.99\n\n//forma 3: parseInt() - para enteros, corta cualquier decimal\nparseInt(\"3.99\")   //3, corta el decimal\nparseInt(\"42px\")   //42, ignora el texto que sigue\n\n//forma 4: el operador + adelante, mas corto, lo veo mucho dentro de callbacks\n+\"42\"     //42\n+\"3.14\"   //3.14\n\n//uso real dentro de filter/reduce, cuando el dato llega como string\npeliculas.filter(pelicula => Number(pelicula.rating) >= 8.0)\npeliculas.filter(pelicula => +pelicula.rating >= 8.0)   //mismo resultado, mas corto\n\n//sacando el promedio de ratings guardados como texto\npeliculas.reduce((acumulador, pelicula) => acumulador + Number(pelicula.rating), 0) / peliculas.length"}]}, {"numero": 80, "titulo": "Operador de Potencia **", "bloque": "funcional", "contenido": [{"tipo": "texto", "texto": "El operador ** eleva un numero a una potencia. Equivale a Math.pow() pero con una sintaxis mas limpia. Siempre requiere el exponente explicitamente."}, {"tipo": "codigo", "codigo": "//sintaxis: base ** exponente\n2 ** 3     //8  (2 al cubo)\n5 ** 2     //25 (al cuadrado)\n9 ** 0.5   //3  (raiz cuadrada)\n\n//es lo mismo que Math.pow() pero mas corto\nMath.pow(2, 3)   //8, mismo resultado\n\n//siempre necesita el exponente, si no marca error\nconst numero = 4\nnumero ** 2   //correcto, al cuadrado\nnumero **      //ERROR, le falta el exponente\n\n//lo use dentro de map para elevar cada elemento al cuadrado\n[1, 2, 3, 4].map(numero => numero ** 2)   //[1, 4, 9, 16]\n\n//numeros negativos necesitan parentesis para que no truene\n(-2) ** 2   //4, correcto\n-2 ** 2     //error de sintaxis en algunos entornos"}]}, {"numero": 81, "titulo": "sort() — Diferencias entre Strings y Numeros", "bloque": "funcional", "contenido": [{"tipo": "texto", "texto": "sort() sin comparador funciona bien para strings alfabeticos, pero falla con numeros porque los convierte a string y los compara por Unicode. Para numeros siempre se necesita el comparador (a, b) => a - b."}, {"tipo": "codigo", "codigo": "//STRINGS - sort() sin comparador funciona bien\n[\"banana\", \"manzana\", \"cereza\"].sort()\n//[\"banana\", \"cereza\", \"manzana\"] - correcto, orden alfabetico\n\n//NUMEROS - sort() sin comparador FALLA\n[10, 1, 21, 2].sort()\n//[1, 10, 2, 21] - INCORRECTO, los esta comparando como si fueran texto\n\n//NUMEROS - con comparador si funciona bien\n[10, 1, 21, 2].sort((a, b) => a - b)   //[1, 2, 10, 21] ascendente\n[10, 1, 21, 2].sort((a, b) => b - a)   //[21, 10, 2, 1] descendente\n\n//como pensar el comparador:\n//a - b menor que 0 -> a va primero (ascendente)\n//a - b mayor que 0 -> b va primero\n\n//importante: sort() muta el array original\n//para no mutarlo, copio primero con spread o slice\nconst original = [10, 1, 21, 2]\nconst ordenado = [...original].sort((a, b) => a - b)   //original queda intacto\nconst ordenado2 = original.slice().sort((a, b) => a - b)   //hace lo mismo"}]}, {"numero": 82, "titulo": "split() con Regex como Delimitador", "bloque": "funcional", "contenido": [{"tipo": "texto", "texto": "split() no solo acepta un string como separador — tambien acepta una regex. Esto permite dividir por multiples caracteres a la vez, como espacios, comas, guiones y puntos juntos."}, {"tipo": "codigo", "codigo": "//split con string - un solo separador\n\"hola mundo\".split(\" \")   //[\"hola\", \"mundo\"]\n\"a,b,c\".split(\",\")          //[\"a\", \"b\", \"c\"]\n\n//split con regex - varios separadores a la vez\n\"Hola Mundo,Soy-Code\".split(/[ ,\\-]/)\n//[\"Hola\", \"Mundo\", \"Soy\", \"Code\"]\n\n//el conjunto [ ,-] dentro de la regex significa:\n//espacio O coma O guion\n//el guion lleva backslash para que no se confunda con un rango dentro de []\n\n//caso real - convertir un titulo en slug para una URL\n\"Curso de JavaScript-Basico.完成\".split(/[ \\-.]/)\n//luego encadeno .map(palabra => palabra.toLowerCase()).join(\"-\")\n\n//split con string vacio - separa caracter por caracter\n\"hola\".split(\"\")   //[\"h\",\"o\",\"l\",\"a\"]"}]}, {"numero": 83, "titulo": "Encadenamiento filter() + reduce()", "bloque": "funcional", "contenido": [{"tipo": "texto", "texto": "filter() y reduce() encadenados permiten calcular sobre un subconjunto de datos sin variables intermedias ni loops. Cada metodo hace una sola cosa: filter selecciona, reduce acumula."}, {"tipo": "codigo", "codigo": "const peliculas = [\n  { titulo: \"Inception\", director: \"Nolan\", rating: \"8.8\" },\n  { titulo: \"Avatar\", director: \"Cameron\", rating: \"7.9\" },\n  { titulo: \"Interstellar\", director: \"Nolan\", rating: \"8.6\" },\n  { titulo: \"Dark Knight\", director: \"Nolan\", rating: \"9.0\" }\n]\n\n//promedio de solo las peliculas de un director en especifico\nconst peliculasDeNolan = peliculas.filter(pelicula => pelicula.director === \"Nolan\")\n\nconst promedio = peliculasDeNolan.reduce((acumulador, pelicula) => {\n  return acumulador + Number(pelicula.rating) / peliculasDeNolan.length\n}, 0)\n//8.8 + 8.6 + 9.0 entre 3 = 8.8\n\n//por que dividir dentro del reduce en cada vuelta:\n//cada suma ya viene proporcional al total, evita tener que\n//dividir hasta el final con una variable extra\n\n//la otra forma, sumando todo y dividiendo al final\nconst suma = peliculasDeNolan.reduce((acumulador, pelicula) => acumulador + Number(pelicula.rating), 0)\nconst promedio2 = suma / peliculasDeNolan.length   //mismo resultado\n\n//como pienso el encadenamiento funcional:\n//filter  -> selecciona QUE elementos voy a procesar\n//map     -> transforma COMO se ven los datos\n//reduce  -> calcula UN resultado final"}]}, {"numero": 84, "titulo": "every() — Verificar que Todos Cumplan una Condicion", "bloque": "funcional", "contenido": [{"tipo": "texto", "texto": "every() recorre el array y devuelve true solo si TODOS los elementos pasan la prueba. Si alguno falla, devuelve false inmediatamente sin revisar el resto. Es como un AND logico aplicado a todo el array."}, {"tipo": "codigo", "codigo": "//every() - TODOS tienen que cumplir la condicion\nconst numeros = [1, 5, 8, 0, 10, 11]\n\nnumeros.every(numero => numero < 10)   //false, el 10 y el 11 no cumplen\nnumeros.every(numero => numero >= 0)   //true, todos son no negativos\n\n//se detiene apenas encuentra uno que no cumple\n[1, 2, -3, 4].every(numero => numero > 0)   //false, se detiene en el -3\n\n//comparando every, some y filter en el mismo array\nconst arr = [1, 2, -3, 4, -5]\n\narr.every(numero => numero > 0)    //false, NO todos son positivos\narr.some(numero => numero > 0)     //true, AL MENOS UNO es positivo\narr.filter(numero => numero > 0)   //[1, 2, 4] LOS QUE son positivos\n\n//caso real - validando que un formulario este completo\nconst camposObligatorios = [\"nombre\", \"email\", \"telefono\"]\nconst formulario = { nombre: \"Jose\", email: \"jose@correo.com\", telefono: \"555\" }\n\nconst formularioCompleto = camposObligatorios.every(campo => formulario[campo] !== \"\")\n//true, todos los campos tienen valor"}]}, {"numero": 85, "titulo": "some() — Verificar que Al Menos Uno Cumpla", "bloque": "funcional", "contenido": [{"tipo": "texto", "texto": "some() recorre el array y devuelve true si AL MENOS UN elemento pasa la prueba. Si encuentra uno que cumple, devuelve true inmediatamente sin revisar el resto. Es como un OR logico aplicado a todo el array."}, {"tipo": "codigo", "codigo": "//some() - AL MENOS UNO tiene que cumplir la condicion\nconst numeros = [10, 50, 8, 220, 110, 11]\n\nnumeros.some(numero => numero < 10)    //true, el 8 cumple\nnumeros.some(numero => numero > 500)   //false, ninguno pasa de 500\n\n//se detiene apenas encuentra el primero que cumple\n[-1, -2, 3, -4].some(numero => numero > 0)   //true, se detiene en el 3\n\n//every es como un AND, some es como un OR\nconst arr = [2, 4, 6, 7, 8]\n\narr.every(numero => numero % 2 === 0)   //false, el 7 no es par\narr.some(numero => numero % 2 !== 0)     //true, el 7 si es impar\n\n//caso real - verificando si un usuario tiene algun permiso en comun con admin\nconst permisosUsuario = [\"leer\", \"comentar\"]\nconst permisosAdmin = [\"leer\", \"escribir\", \"eliminar\", \"administrar\"]\n\nconst tieneAcceso = permisosAdmin.some(permiso => permisosUsuario.includes(permiso))\n//true, \"leer\" esta en los dos arrays"}]}, {"numero": 86, "titulo": "Currying — Funciones que Devuelven Funciones", "bloque": "funcional", "contenido": [{"tipo": "texto", "texto": "Currificar una funcion significa convertirla de recibir N argumentos de golpe a recibir un argumento a la vez, devolviendo una nueva funcion por cada uno. Es util cuando no tienes todos los argumentos disponibles al mismo tiempo."}, {"tipo": "codigo", "codigo": "//funcion normal - necesita todos los argumentos de una vez\nfunction sumarTres(x, y, z) {\n  return x + y + z\n}\nsumarTres(1, 2, 3)   //6\n\n//funcion currificada - un argumento a la vez, cada una devuelve la siguiente\nconst sumarCurried = (x) => (y) => (z) => x + y + z\nsumarCurried(1)(2)(3)   //6\n\n//paso a paso de que va devolviendo cada llamada:\n//sumarCurried(1)       -> devuelve: (y) => (z) => 1 + y + z\n//sumarCurried(1)(2)    -> devuelve: (z) => 1 + 2 + z\n//sumarCurried(1)(2)(3) -> ejecuta:  1 + 2 + 3 = 6\n\n//util cuando no tengo todos los argumentos al mismo tiempo\nconst agregarImpuesto = (tasa) => (precio) => precio + (precio * tasa)\n\nconst conIVA = agregarImpuesto(0.16)   //guardo la funcion con la tasa ya fija\nconIVA(100)   //116, aplica el IVA cuando por fin tengo el precio\nconIVA(200)   //232\nconIVA(500)   //580\n\n//error que casi cometo - crear una funcion interna que pisa el argumento externo\nfunction sumarDos(x) {\n  const fn = x => y => x + y   //MAL, este x de adentro tapa al x de sumarDos\n  return fn\n}\n//correccion - sumarDos ya recibe su x, solo hace falta devolver la cadena\nfunction sumarDos(x) {\n  return y => x + y\n}"}]}], "actualizado": "julio 2026", "total": 86};
